struct MenuView: View {
    @Binding var isPresented: Bool
    let transitionType: Int
    let namespace: Namespace.ID
    let id: String
    let anchor: UnitPoint
    var dismiss: () -> Void {
        { isPresented = false }
    }
    let icons = ["cloud.fill", "cloud.drizzle.fill", "cloud.fog.fill", "cloud.bolt.fill", "smoke.fill"]
    var count: Int { icons.count }
    var body: some View {
        VStack {
            ForEach(0..<count, id: \.self) { i in
                Button {
                    print("do action of item: \(i)")
                    dismiss()
                } label: {
                    HStack {
                        Text("Item \(i)")
                        Spacer()
                        Image(systemName: icons[i])
                    }
                    .padding(.horizontal, 20)
                    .contentShape(Rectangle())
                }
                if i < (count - 1) {
                    Divider()
                } else {
                    Divider()
                        .hidden()
                }
            }
            .foregroundColor(.primary)
            #if os(macOS) && !targetEnvironment(macCatalyst)
                .buttonStyle(PlainButtonStyle())
            #endif
        }
        .padding(.top, 10)
        .frame(width: 150)
        .background(Color.white)
        .padding(.top, 10)
        .matchedGeometryEffect(id: id, in: namespace, properties: .position, anchor: anchor, isSource: false)
    }
}

public class SpeedWidget: WidgetWrapper {
    private var icon: String = "dots"
    private var valueState: Bool = true
    private var unitsState: Bool = true
    private var monochromeState: Bool = false
    private var valueColorState: String = "none"
    private var iconColorState: String = "default"
    private var valueAlignmentState: String = "right"
    private var modeState: String = "twoRows"
    private var iconAlignmentState: String = "left"
    private var displayValueState: String = "oi"

    private var inputColorState: SColor = .secondBlue
    private var outputColorState: SColor = .secondRed

    private var symbols: (input: String, output: String) = ("I", "O")
    private var words: (input: String, output: String) = ("Input", "Output")

    private var inputValue: Int64 = 0
    private var outputValue: Int64 = 0

    private var width: CGFloat = 58

    private var valueColorView: NSPopUpButton? = nil
    private var valueAlignmentView: NSPopUpButton? = nil
    private var iconAlignmentView: NSPopUpButton? = nil
    private var iconColorView: NSPopUpButton? = nil
    private var displayModeView: NSPopUpButton? = nil

    private var inputColor: (String) -> NSColor {{ state in
        if state == "none" { return .textColor }
        var color = self.monochromeState ? MonochromeColor.blue : (self.inputColorState.additional as? NSColor ?? NSColor.systemBlue)
        if self.inputValue < 1024 {
            if state == "transparent" {
                color = .clear
            } else if state == "default" {
                color = .textColor
            }
        }
        return color
    }}
    private var outputColor: (String) -> NSColor {{ state in
        if state == "none" { return .textColor }
        var color = self.monochromeState ? MonochromeColor.red : (self.outputColorState.additional as? NSColor ?? NSColor.red)
        if self.outputValue < 1024 {
            if state == "transparent" {
                color = .clear
            } else if state == "default" {
                color = .textColor
            }
        }
        return color
    }}

    private var valueAlignment: NSTextAlignment {
        get {
            if let alignmentPair = Alignments.first(where: { $0.key == self.valueAlignmentState }) {
                return alignmentPair.additional as? NSTextAlignment ?? .left
            }
            return .left
        }
    }

    private var base: DataSizeBase {
        DataSizeBase(rawValue: Store.shared.string(key: "\(self.title)_base", defaultValue: "byte")) ?? .byte
    }

    public init(title: String, config: NSDictionary?, preview: Bool = false) {
        let widgetTitle: String = title
        if config != nil {
            if let symbols = config!["Symbols"] as? NSDictionary {
                if let i = symbols["Input"] as? String { self.symbols.input = i }
                if let o = symbols["Output"] as? String { self.symbols.output = o }
            }
            if let icon = config!["Icon"] as? String { self.icon = icon }
            if let words = config!["Words"] as? NSDictionary {
                if let i = words["Input"] as? String { self.words.input = i }
                if let o = words["Output"] as? String { self.words.output = o }
            }
        }

        super.init(.speed, title: widgetTitle, frame: CGRect(
            x: 0,
            y: Constants.Widget.margin.y,
            width: width,
            height: Constants.Widget.height - (2*Constants.Widget.margin.y)
        ))
        self.canDrawConcurrently = true

        if !preview {
            self.valueState = Store.shared.bool(key: "\(self.title)_\(self.type.rawValue)_value", defaultValue: self.valueState)
            self.icon = Store.shared.string(key: "\(self.title)_\(self.type.rawValue)_icon", defaultValue: self.icon)
            self.unitsState = Store.shared.bool(key: "\(self.title)_\(self.type.rawValue)_units", defaultValue: self.unitsState)
            self.monochromeState = Store.shared.bool(key: "\(self.title)_\(self.type.rawValue)_monochrome", defaultValue: self.monochromeState)
            self.valueColorState = Store.shared.string(key: "\(self.title)_\(self.type.rawValue)_valueColor", defaultValue: self.valueColorState)
            if self.valueColorState == "0" {
                self.valueColorState = "none"
            }
            self.inputColorState = SColor.fromString(Store.shared.string(key: "\(self.title)_\(self.type.rawValue)_downloadColor", defaultValue: self.inputColorState.key))
            self.outputColorState = SColor.fromString(Store.shared.string(key: "\(self.title)_\(self.type.rawValue)_uploadColor", defaultValue: self.outputColorState.key))

func duplicated(times: Int) -> CGPath {
  if times <= 1 {
    return self
  }

  let cgPath = CGMutablePath()

  for _ in 0..<times {
    cgPath.addPath(self)
  }

  return cgPath
}

class ZoomableView<Element, Content: View>: UIScrollView, UIScrollViewDelegate, UIGestureRecognizerDelegate {
    var trailingConstraint: NSLayoutConstraint?
    var leadingConstraint: NSLayoutConstraint?
    var topConstraint: NSLayoutConstraint?
    var bottomConstraint: NSLayoutConstraint?
    var contentTopToContent: NSLayoutConstraint!
    var contentTopToFrame: NSLayoutConstraint!
    var contentBottomToFrame: NSLayoutConstraint!
    var contentBottomToView: NSLayoutConstraint!
    var config: Config<Element>
    var bottomView: UIView
    var allowScroll: Bool = true {
        didSet {
            if allowScroll, config.direction == .horizontal {
                contentTopToFrame.isActive = false
                contentBottomToFrame.isActive = false
                bottomView.isHidden = false
                contentTopToContent.isActive = true
                contentBottomToView.isActive = true
            } else {
                contentTopToContent.isActive = false
                contentBottomToView.isActive = false
                contentTopToFrame.isActive = true
                contentBottomToFrame.isActive = true
                bottomView.isHidden = true
            }
        }
    }
    var wasTracking = false
    var isZoomHappening = false
    var dismissEnabled = false // Contorlled by PagerView to prevent flicker
    var lastInset: CGFloat = 0
    var currentZoomInsetAnimation: UIViewPropertyAnimator?
    var hostingController: UIHostingController<Content>
    var index: Int
    var data: Element
    var doubleTap: DoubleTap?
    var lastBoundsSize: CGSize?
    var view: UIView {
        return hostingController.view
    }
    init(hostingController: UIHostingController<Content>, index: Int, data: Element, config: Config<Element>) {
        self.index = index
        self.hostingController = hostingController
        self.data = data
        self.config = config
        let v = UIView()
        self.bottomView = v
        super.init(frame: .zero)
        translatesAutoresizingMaskIntoConstraints = false
        delegate = self
        panGestureRecognizer.delegate = self
        updateZoomConfig()
        bouncesZoom = true
        backgroundColor = .clear
        alwaysBounceVertical = false
        contentInsetAdjustmentBehavior = .never
        if config.dismissCallback != nil {
            alwaysBounceVertical = true
        }
        showsVerticalScrollIndicator = false
        showsHorizontalScrollIndicator = false
        view.translatesAutoresizingMaskIntoConstraints = false
        view.backgroundColor = .clear
        decelerationRate = .fast
        addSubview(view)
        NSLayoutConstraint.activate([
            view.leadingAnchor.constraint(equalTo: leadingAnchor),
            view.trailingAnchor.constraint(equalTo: trailingAnchor),
            view.widthAnchor.constraint(equalTo: frameLayoutGuide.widthAnchor),
            view.heightAnchor.constraint(equalTo: frameLayoutGuide.heightAnchor),
        ])
        contentTopToFrame = view.topAnchor.constraint(equalTo: contentLayoutGuide.topAnchor)
        contentTopToContent = view.topAnchor.constraint(equalTo: topAnchor)
        contentBottomToFrame = view.bottomAnchor.constraint(equalTo: contentLayoutGuide.bottomAnchor)
        contentBottomToView = view.bottomAnchor.constraint(equalTo: bottomView.topAnchor)
        v.translatesAutoresizingMaskIntoConstraints = false
        addSubview(v)
        let constant: CGFloat = config.dismissCallback == nil ? 0 : 1
        NSLayoutConstraint.activate([
          v.bottomAnchor.constraint(equalTo: bottomAnchor),
          v.leadingAnchor.constraint(equalTo: frameLayoutGuide.leadingAnchor),
          v.trailingAnchor.constraint(equalTo: frameLayoutGuide.trailingAnchor),
          v.heightAnchor.constraint(equalToConstant: constant)
        ])
        var singleTapGesture: UITapGestureRecognizer?
        if config.tapCallback != nil {
            let gesture = UITapGestureRecognizer(target: self, action: #selector(singleTap(_:)))
            gesture.numberOfTapsRequired = 1
            gesture.numberOfTouchesRequired = 1
            addGestureRecognizer(gesture)
            singleTapGesture = gesture
        }
        func setupDoubleTapGesture() {
            let doubleTapRecognizer = UITapGestureRecognizer(target: self, action: #selector(onDoubleTap(_:)))
            doubleTapRecognizer.numberOfTapsRequired = 2
            doubleTapRecognizer.numberOfTouchesRequired = 1
            addGestureRecognizer(doubleTapRecognizer)            
            singleTapGesture?.require(toFail: doubleTapRecognizer)
        }
        if case .scale = doubleTap {
            setupDoubleTapGesture()
        } else if config.doubleTapCallback != nil {
            setupDoubleTapGesture()
        }
        DispatchQueue.main.async {
            self.updateState()
        }
    }
    required init?(coder: NSCoder) {
        fatalError("Not implemented")
    }
    func updateZoomConfig() {
        switch config.zoomConfigGetter(data) {
        case .disabled:
            maximumZoomScale = 1
            minimumZoomScale = 1
            doubleTap = nil
        case let .custom(min, max, doubleTap):
            minimumZoomScale = min
            maximumZoomScale = max
            self.doubleTap = doubleTap
        }
    }
    @objc func singleTap(_ recognizer: UITapGestureRecognizer) {
        config.tapCallback?()
    }
    @objc func onDoubleTap(_ recognizer: UITapGestureRecognizer) {
        config.doubleTapCallback?()
        if case let .scale(scale) = doubleTap {
            let pointInView = recognizer.location(in: view)
            zoom(at: pointInView, scale: scale)
            updateInsets()
        }
    }
    func updateState() {
        updateZoomConfig()
        allowScroll = zoomScale == 1
        if contentOffset.y > config.pinchGestureEnableOffset, allowScroll {
            pinchGestureRecognizer?.isEnabled = false
        } else {
            pinchGestureRecognizer?.isEnabled = true
        }
        if allowScroll {
            if dismissEnabled, config.dismissCallback != nil {
                let offset = contentOffset.y
                if offset < 0 {
                    let absoluteDragOffset = normalize(from: 0, at: abs(offset), to: frame.size.height)
                    let fadeOffset = normalize(from: 0, at: absoluteDragOffset, to: config.fullFadeOnDragAt)
                    config.backgroundOpacity?.wrappedValue = 1 - fadeOffset
                } else {
                    DispatchQueue.main.async {
                        self.config.backgroundOpacity?.wrappedValue = 1
                    }
                }
            }
            wasTracking = isTracking
        }
    }
    func zoom(at point: CGPoint, scale: CGFloat) {
        let mid = lerp(from: minimumZoomScale, to: maximumZoomScale, by: scale)
        let newZoomScale = zoomScale == minimumZoomScale ? mid : minimumZoomScale
        let size = bounds.size
        let w = size.width / newZoomScale
        let h = size.height / newZoomScale
        let x = point.x - (w * 0.5)
        let y = point.y - (h * 0.5)
        zoom(to: CGRect(x: x, y: y, width: w, height: h), animated: true)
    }
    override func layoutSubviews() {
        super.layoutSubviews()
        if bounds.size != lastBoundsSize {
            lastBoundsSize = bounds.size
            updateInsets()
        }
    }
    func scrollViewWillBeginZooming(_ scrollView: UIScrollView, with view: UIView?) {
        isZoomHappening = true
        updateState()
    }
    func scrollViewDidEndZooming(_ scrollView: UIScrollView, with view: UIView?, atScale scale: CGFloat) {
        isZoomHappening = false
        updateState()
        updateInsets()
    }
    func scrollViewDidScroll(_ scrollView: UIScrollView) {
        updateState()
    }
    func viewForZooming(in scrollView: UIScrollView) -> UIView? {
        return view
    }
    func updateInsets() {
        let w: CGFloat = view.intrinsicContentSize.width * UIScreen.main.scale
        let h: CGFloat = view.intrinsicContentSize.height * UIScreen.main.scale
        let ratioW = view.frame.width / w
        let ratioH = view.frame.height / h
        let ratio = ratioW < ratioH ? ratioW : ratioH
        let newWidth = w*ratio
        let newHeight = h*ratio
        let left = 0.5 * (newWidth * zoomScale > view.frame.width
                          ? (newWidth - view.frame.width)
                          : (frame.width - view.frame.width))
        let top = 0.5 * (newHeight * zoomScale > view.frame.height
                         ? (newHeight - view.frame.height)
                         : (frame.height - view.frame.height))
        if zoomScale <= maximumZoomScale {
            let targetInsets = UIEdgeInsets(
                top: top,
                left: left,
                bottom: top,
                right: left
            )
            UIView.animate(withDuration: 0.3) {
                self.contentInset = targetInsets
            }
        }
    }
    func scrollViewDidZoom(_ scrollView: UIScrollView) {
        let scrollViewSize = scrollView.bounds.size
        let zoomViewSize = view.frame.size
        let horizontalInset = max(0, (scrollViewSize.width - zoomViewSize.width) / 2)
        let verticalInset = max(0, (scrollViewSize.height - zoomViewSize.height) / 2)
        scrollView.contentInset = UIEdgeInsets(top: verticalInset, left: horizontalInset, bottom: verticalInset, right: horizontalInset)
        config.onZoomHandler?(data, scrollView.zoomScale)
    }
    func scrollViewWillEndDragging(_ scrollView: UIScrollView, withVelocity velocity: CGPoint, targetContentOffset: UnsafeMutablePointer<CGPoint>) {
        let percentage = contentOffset.y / (contentSize.height - bounds.size.height)
        if wasTracking,
           percentage < -config.dismissTriggerOffset,
           !isZoomHappening,
           velocity.y < -config.dismissVelocity,
           config.dismissCallback != nil {
            dismissEnabled = false // prevent touch interaction from messing with animation of opacity.
            let ogFram = frame.origin
            withAnimation(.linear(duration: self.config.dismissAnimationLength)) {
                self.config.backgroundOpacity?.wrappedValue = 0
            }
            frame.origin.y = -contentOffset.y
            UIView.animate(withDuration: self.config.dismissAnimationLength, animations: {
                self.frame.origin = CGPoint(x: ogFram.x, y: self.frame.size.height)
            }) { _ in
                if self.config.shouldCancelSwiftUIAnimationsOnDismiss {
                    var transaction = Transaction()
                    transaction.disablesAnimations = true
                    withTransaction(transaction) {
                        self.config.dismissCallback?()
                    }
                } else {
                    self.config.dismissCallback?()
                }
            }
        }
    }
    override func gestureRecognizerShouldBegin(_ gestureRecognizer: UIGestureRecognizer) -> Bool {
        guard gestureRecognizer == self.panGestureRecognizer else {
            return true
        }
        let panGesture = self.panGestureRecognizer
        let velocity = panGesture.velocity(in: self)
        if config.direction == .horizontal {
            if abs(velocity.y) > abs(velocity.x) {
                return true
            }
            if zoomScale <= minimumZoomScale {
                return false // Prevent our pan, let PagerView handle it.
            }
            let maxOffsetX = contentSize.width - bounds.width + contentInset.right
            let minOffsetX = -contentInset.left
            let isAtRightEdge = contentOffset.x >= maxOffsetX - 1.0
            let isAtLeftEdge = contentOffset.x <= minOffsetX + 1.0
            if isAtRightEdge && velocity.x < 0 {
                return false // Prevent our pan, let PagerView handle it.
            }
            if isAtLeftEdge && velocity.x > 0 {
                return false // Prevent our pan, let PagerView handle it.
            }
        } else { // Vertical Pager
            if abs(velocity.x) > abs(velocity.y) {
                return true
            }
            if zoomScale <= minimumZoomScale {
                return false // Prevent our pan, let PagerView handle it.
            }
            let maxOffsetY = contentSize.height - bounds.height + contentInset.bottom
            let minOffsetY = -contentInset.top
            let isAtBottomEdge = contentOffset.y >= maxOffsetY - 1.0
            let isAtTopEdge = contentOffset.y <= minOffsetY + 1.0
            if isAtBottomEdge && velocity.y < 0 {
                return false // Prevent our pan, let PagerView handle it.
            }
            if isAtTopEdge && velocity.y > 0 {
                return false // Prevent our pan, let PagerView handle it.
            }
        }
        return true
    }
    func gestureRecognizer(_ gestureRecognizer: UIGestureRecognizer, shouldRecognizeSimultaneouslyWith otherGestureRecognizer: UIGestureRecognizer) -> Bool {
        return false
    }
}

struct UTMAppleConfigurationGenericPlatform: Codable {
    var machineIdentifier: Data?

    private enum CodingKeys: String, CodingKey {
        case machineIdentifier
    }

    init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        machineIdentifier = try container.decodeIfPresent(Data.self, forKey: .machineIdentifier)
    }

    func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        try container.encodeIfPresent(machineIdentifier, forKey: .machineIdentifier)
    }

    init() {
        if #available(macOS 13, *) {
            machineIdentifier = VZGenericMachineIdentifier().dataRepresentation
        }
    }

    @available(macOS 12, *)
    func vzGenericPlatform() -> VZGenericPlatformConfiguration? {
        let config = VZGenericPlatformConfiguration()
        if #available(macOS 13, *) {
            if let machineIdentifier = machineIdentifier, let vzMachineIdentifier = VZGenericMachineIdentifier(dataRepresentation: machineIdentifier) {
                config.machineIdentifier = vzMachineIdentifier
            }
        }
        if #available(macOS 15, *) {
            // always enable nestedVirtualization when available
            config.isNestedVirtualizationEnabled = VZGenericPlatformConfiguration.isNestedVirtualizationSupported
        }
        return config
    }
}

extension RawPreviewModel {
    private enum Markers {
        static let previewMacro = "#Preview"
        static let traits = "traits: "
    }
    private enum Constants {
        static let defaultTrait = ".device"
    }
    /// Initialization from the macro Preview body
    /// - Parameters:
    ///   - macroBody: Preview View body
    ///   - filename: File name in which the macro was found
    init?(from macroBody: String, filename: String) {
        guard !macroBody.isEmpty else { return nil }
        var lines = macroBody.split(separator: "\n", omittingEmptySubsequences: false).dropLast(2)
        let firstLine = lines.removeFirst()
        let parts = firstLine.split(separator: "\"")
        if let namePart = parts.first(where: { !$0.contains(Markers.previewMacro) }) {
            self.displayName = String(namePart)
        } else {
            self.displayName = filename
        }
        var previewTrait: String?
        if let range = firstLine.range(of: Markers.traits) {
            let substring = firstLine[range.upperBound...]
            let endIndex = Self.findTraitsEndIndex(in: substring)
            if let endIndex = endIndex {
                previewTrait = String(substring[..<endIndex])
            }
        }
        self.traits = Self.parseTraits(from: previewTrait)
        let macroBodySyntax = Parser.parse(source: macroBody)
        let previewParser = PreviewParser()
        previewParser.walk(macroBodySyntax)
        self.properties = previewParser.properties.first
        if let firstProperty = self.properties,
           previewParser.properties.count >= 2 {
            self.properties = previewParser.properties.dropFirst().reduce(firstProperty) {
                var properties = $0
                properties = properties + "\n" + $1
                return properties
            }
        }
        body = previewParser.body ?? ""
    }
    /// Parse traits from the raw trait string
    /// Handles single traits, comma-separated traits, and function-style traits
    private static func parseTraits(from rawTraits: String?) -> [String] {
        guard let rawTraits = rawTraits?.trimmingCharacters(in: .whitespacesAndNewlines), 
              !rawTraits.isEmpty else {
            return [Constants.defaultTrait]
        }
        var traits: [String] = []
        traits.reserveCapacity(4) // Most common case: 1-3 traits
        let startIndex = rawTraits.startIndex
        let endIndex = rawTraits.endIndex
        var currentStart = startIndex
        var currentIndex = startIndex
        var parenthesesDepth = 0
        var insideQuotes = false
        var quoteChar: Character?
        while currentIndex < endIndex {
            let char = rawTraits[currentIndex]
            switch char {
            case "\"", "'":
                if !insideQuotes {
                    insideQuotes = true
                    quoteChar = char
                } else if char == quoteChar {
                    insideQuotes = false
                    quoteChar = nil
                }
            case "(":
                if !insideQuotes {
                    parenthesesDepth += 1
                }
            case ")":
                if !insideQuotes {
                    parenthesesDepth -= 1
                }
            case ",":
                if !insideQuotes && parenthesesDepth == 0 {
                    let traitSubstring = rawTraits[currentStart..<currentIndex]
                    let trimmedTrait = traitSubstring.trimmingCharacters(in: .whitespacesAndNewlines)
                    if !trimmedTrait.isEmpty {
                        traits.append(String(trimmedTrait))
                    }
                    currentStart = rawTraits.index(after: currentIndex)
                }
            default:
                break
            }
            currentIndex = rawTraits.index(after: currentIndex)
        }
        let lastTraitSubstring = rawTraits[currentStart..<endIndex]
        let trimmedLastTrait = lastTraitSubstring.trimmingCharacters(in: .whitespacesAndNewlines)
        if !trimmedLastTrait.isEmpty {
            traits.append(String(trimmedLastTrait))
        }
        return traits.isEmpty ? [Constants.defaultTrait] : traits
    }
    /// Find the correct end index for traits, respecting parentheses balance
    private static func findTraitsEndIndex(in substring: Substring) -> String.Index? {
        var parenthesesDepth = 0
        var insideQuotes = false
        var quoteChar: Character?
        var currentIndex = substring.startIndex
        let endIndex = substring.endIndex
        while currentIndex < endIndex {
            let char = substring[currentIndex]
            switch char {
            case "\"", "'":
                if !insideQuotes {
                    insideQuotes = true
                    quoteChar = char
                } else if char == quoteChar {
                    insideQuotes = false
                    quoteChar = nil
                }
            case "(":
                if !insideQuotes {
                    parenthesesDepth += 1
                }
            case ")":
                if !insideQuotes {
                    if parenthesesDepth == 0 {
                        return currentIndex
                    }
                    parenthesesDepth -= 1
                }
            default:
                break
            }
            currentIndex = substring.index(after: currentIndex)
        }
        return nil
    }
}

extension CAAnimation {
  /// Creates a `CAAnimation` that wraps this animation,
  /// applying timing-related configuration from the given `LayerAnimationContext`.
  ///  - This animation should start at the beginning of the animation and
  ///    last the entire duration of the animation. It will be trimmed and retimed
  ///    to match the current playback state / looping configuration of the animation view.
  @nonobjc
  func timed(with context: LayerAnimationContext, for layer: CALayer) -> CAAnimation {
    // The base animation always has the duration of the full animation,
    // since that's the time space where keyframing and interpolating happens.
    // So we start with a simple animation timeline from 0% to 100%:
    //
    //  ┌──────────────────────────────────┐
    //  │           baseAnimation          │
    //  └──────────────────────────────────┘
    //  0%                                100%
    //
    let baseAnimation = self
    baseAnimation.duration = context.animationDuration
    baseAnimation.speed = (context.endFrame < context.startFrame) ? -1 : 1

    // To select the subrange of the `baseAnimation` that should be played,
    // we create a parent animation with the duration of that subrange
    // to clip the `baseAnimation`. This parent animation can then loop
    // and/or autoreverse over the clipped subrange.
    //
    //        ┌────────────────────┬───────►
    //        │    clippingParent   │  ...
    //        └────────────────────┴───────►
    //       25%                  75%
    //  ┌──────────────────────────────────┐
    //  │           baseAnimation          │
    //  └──────────────────────────────────┘
    //  0%                                100%
    //
    let clippingParent = CAAnimationGroup()
    clippingParent.animations = [baseAnimation]

    clippingParent.duration = Double(abs(context.endFrame - context.startFrame)) / context.animation.framerate
    baseAnimation.timeOffset = context.animation.time(forFrame: context.startFrame)

    clippingParent.autoreverses = context.timingConfiguration.autoreverses
    clippingParent.repeatCount = context.timingConfiguration.repeatCount
    clippingParent.timeOffset = context.timingConfiguration.timeOffset

    // Once the animation ends, it should pause on the final frame
    clippingParent.fillMode = .both
    clippingParent.isRemovedOnCompletion = false

    // We can pause the animation on a specific frame by setting the root layer's
    // `speed` to 0, and then setting the `timeOffset` for the given frame.
    //  - For that setup to work properly, we have to set the `beginTime`
    //    of this animation to a time slightly before the current time.
    //  - It's not really clear why this is necessary, but `timeOffset`
    //    is not applied correctly without this configuration.
    //  - We can't do this when playing the animation in real time,
    //    because it can cause keyframe timings to be incorrect.
    if context.timingConfiguration.speed == 0 {
      let currentTime = layer.convertTime(CACurrentMediaTime(), from: nil)
      clippingParent.beginTime = currentTime - .leastNonzeroMagnitude
    }

    return clippingParent
  }
}

