                <string>launch</string>
                <key>CFBundleSupportedPlatforms</key>
                <array>
                    <string>MacOSX</string>
                </array>
                <key>LSMinimumSystemVersion</key>
                <string>14.0</string>
                <key>LSApplicationCategoryType</key>
                <string>public.app-category.games</string>
            </dict>
            </plist>
            """
            try info.write(to: contents.appending(path: "Info")
                                       .appendingPathExtension("plist"),
                           atomically: false,
                           encoding: .utf8)

            // Set bundle icon
            let request = QLThumbnailGenerator.Request(fileAt: program.url,
                                                       size: CGSize(width: 512, height: 512),
                                                       scale: 2.0,
                                                       representationTypes: .thumbnail)
            let thumbnail = try await QLThumbnailGenerator.shared.generateBestRepresentation(for: request)
            NSWorkspace.shared.setIcon(thumbnail.nsImage,
                                       forFile: app.path(percentEncoded: false),
                                       options: NSWorkspace.IconCreationOptions())
            NSWorkspace.shared.activateFileViewerSelecting([app])
        } catch {
            print(error)
        }
    }
}

extension CGPath {
  /// Duplicates this `CGPath` so that it is repeated the given number of times
  func duplicated(times: Int) -> CGPath {
    if times <= 1 {
      return self
    }

    let cgPath = CGMutablePath()

    for _ in 0..<times {
      cgPath.addPath(self)
    }

    return cgPath
  }
