final class RectangleDrawingTool: DrawingTool {
    typealias Stroke = RectangleStroke
    static func drawStroke(_ stroke: RectangleStroke, inContext context: CGContext) {
        context.setBlendMode(.copy)
        context.setStrokeColor(stroke.strokeColor.cgColor)
        context.setLineWidth(stroke.strokeWidth)
        context.stroke(.init(from: stroke.startPoint, to: stroke.endPoint))
    }
    var delegate: DrawingToolDelegate?
    let strokeColor: UIColor
    let strokeWidth: CGFloat
    var startPoint: CGPoint?
    var endPoint: CGPoint?
    init(strokeColor: UIColor, strokeWidth: CGFloat) {
        self.strokeColor = strokeColor
        self.strokeWidth = strokeWidth
    }
    func startedPan(atPoint point: CGPoint) {
        startPoint = point
    }
    func continuedPan(atPoint point: CGPoint) {
        guard let startPoint else { return }
        endPoint = point
        delegate?.drawingToolSetNeedsDisplay(self)
    }
    func finishedPan(atPoint point: CGPoint) {
        guard let startPoint else { return }
        let stroke = Stroke(
            strokeColor: strokeColor,
            strokeWidth: strokeWidth,
            startPoint: startPoint,
            endPoint: point
        )
        self.startPoint = nil
        self.endPoint = nil
        delegate?.drawingTool(self, didCreateStroke: stroke)
    }
    func drawCurrentStroke(inContext context: CGContext) {
        guard let startPoint, let endPoint else { return }
        context.setBlendMode(.copy)
        context.setStrokeColor(strokeColor.cgColor)
        context.setLineWidth(strokeWidth)
        context.stroke(.init(from: startPoint, to: endPoint))
    }
}

struct GeneratedPlaybookOptions {
    var targetPath: String?
    var sources: [Path]
    var output: Path
    var previewDefaultEnabled: Bool
    var template: Path?
    var cacheBasePath: Path?
    var imports: [String]?
    var testableImports: [String]?
    init(targetPath: String?, sources: [String], output: String?, template: String?, cacheBasePath: String?, config: Config?) throws {
        self.targetPath = config?.playbook.targetPath ?? targetPath
        self.sources = sources.isEmpty ? [.current] : sources.compactMap({ Path($0) })
        self.output = (output.flatMap({ Path($0) }) ?? .current) + Constants.defaultOutputName
        previewDefaultEnabled = config?.playbook.previewDefaultEnabled ?? true
        if let template = config?.playbook.template, let targetPath {
            let targetURL = URL(filePath: targetPath)
            let templateURL = targetURL.appending(path: template)
            self.template = Path(templateURL.absoluteURL.path(percentEncoded: false))
        } else if let template {
            self.template = Path(template)
        }
        self.cacheBasePath = cacheBasePath.flatMap({ Path($0) })
        imports = config?.playbook.imports
        testableImports = config?.playbook.testableImports
    }
}

final class EraserDrawingTool: DrawingTool {
    typealias Stroke = EraserStroke
    static func drawStroke(_ stroke: EraserStroke, inContext context: CGContext) {
        context.setBlendMode(.copy)
        context.setStrokeColor(UIColor.clear.cgColor)
        context.setLineWidth(stroke.strokeWidth)
        for (index, point) in stroke.points.enumerated() {
            switch index {
            case 0:
                context.move(to: point)
            default:
                context.addLine(to: point)
            }
        }
        context.strokePath()
    }
    var delegate: DrawingToolDelegate?
    let strokeWidth: CGFloat
    var currentStrokePoints: [CGPoint] = []
    init(strokeWidth: CGFloat) {
        self.strokeWidth = strokeWidth
    }
    func startedPan(atPoint point: CGPoint) {
        currentStrokePoints = [point]
    }
    func continuedPan(atPoint point: CGPoint) {
        currentStrokePoints.append(point)
        delegate?.drawingToolSetNeedsDisplay(self)
    }
    func finishedPan(atPoint point: CGPoint) {
        currentStrokePoints.append(point)
        guard currentStrokePoints.count > 1 else { return }
        let strokeInfo = Stroke(
            strokeWidth: strokeWidth,
            points: currentStrokePoints
        )
        currentStrokePoints = []
        delegate?.drawingTool(self, didCreateStroke: strokeInfo)
        delegate?.drawingToolSetNeedsDisplay(self)
    }
    func drawCurrentStroke(inContext context: CGContext) {
        guard currentStrokePoints.count > 1 else { return }
        context.setBlendMode(.copy)
        context.setStrokeColor(UIColor.clear.cgColor)
        context.setLineWidth(strokeWidth)
        for (index, point) in currentStrokePoints.enumerated() {
            switch index {
            case 0:
                context.move(to: point)
            default:
                context.addLine(to: point)
            }
        }
        context.strokePath()
    }
}

struct Home: View {
    @State var dragOffset: CGSize = .zero
    @State var startAnimation: Bool = true
    @State var selected: MetaballOption = .single
    var body: some View {
        VStack {
            Text("Metaball Animation")
                .font(.title)
                .fontWeight(.semibold)
                .frame(maxWidth: .infinity, alignment: .leading)
                .padding(15)
            Picker("", selection: $selected) {
                ForEach(MetaballOption.allCases, id: \.self) { option in
                    Text(option.rawValue)
                }
            }
            .pickerStyle(.segmented)
            .padding(.horizontal, 15)
            switch selected {
            case .single:
                SingleMetaBall()
            case .clubbed:
                ClubbedView()
            }
        }
    }
    /// Metaballがウニョウニョ動くのを見て楽しみます
    /// - Returns: 複数のボールが融合するView
    func ClubbedView() -> some View {
        let numberOfBalls = 15 // Ballの数を指定する
        let ballIndexes = 1...numberOfBalls
        let animationCycle = 2.0 // アニメーションの周期 (秒) how long the animation needs to be changed
        let ballMovingTime = 1.9 // Ballが移動する時間 (秒)
        return Rectangle()
            .fill(theGradient)
            .mask({
                TimelineView(.animation(minimumInterval: animationCycle, paused: false)) { _ in
                    Canvas { context, size in
                        context.addFilter(.alphaThreshold(min: 0.5, color: .white))
                        context.addFilter(.blur(radius: 30))
                        context.drawLayer { layerContext in
                            for index in ballIndexes {
                                if let resolvedView = context.resolveSymbol(id: index) {
                                    layerContext.draw(resolvedView, at: CGPoint(x: size.width / 2, y: size.height / 2))
                                }
                            }
                        }
                    } symbols: {
                        ForEach(ballIndexes, id: \.self) { index in
                            let offset   = startAnimation
                                ? CGSize(width: .random(in: -180...180), height: .random(in: -240...240)) // Ballが動き回る範囲
                                : .zero
                            let diameter = startAnimation ? CGFloat.random(in: 120...160) : 140 // Ballの直径
                            Ball(offset: offset, diameter: diameter)
                                .tag(index)
                                .animation(.easeOut(duration: ballMovingTime), value: offset)
                        }
                    }
                }
            })
            .contentShape(Rectangle())
            .onTapGesture {
                startAnimation.toggle()
            }
    }
    /// Metaballをドラッグして楽しみます
    /// - Returns: ボールが2つのView
    func SingleMetaBall() -> some View {
        let centerBallIndex  = 0
        let draggedBallIndex = 1
        return Rectangle()
            .fill(theGradient)
            .mask {
                Canvas { context, size in
                    context.addFilter(.alphaThreshold(min: 0.5, color: .white))
                    context.addFilter(.blur(radius: 35))
                    context.drawLayer { layerContext in
                        for index in [centerBallIndex, draggedBallIndex] {
                            if let resolvedView = context.resolveSymbol(id: index) {
                                layerContext.draw(resolvedView, at: CGPoint(x: size.width / 2, y: size.height / 2))
                            }
                        }
                    }
                } symbols: {
                    Ball()
                        .tag(centerBallIndex)
                    Ball(offset: dragOffset)
                        .tag(draggedBallIndex)
                }
            }
            .gesture(
                DragGesture()
                    .onChanged { value in
                        dragOffset = value.translation
                    }
                    .onEnded { _ in
                        withAnimation(.interactiveSpring(response: 0.6, dampingFraction: 0.7, blendDuration: 0.7)) {
                            dragOffset = .zero
                        }
                    }
            )
    }
    /// ボール１個を生成する
    /// - Parameters:
    ///   - offset: ボール中心からのオフセット
    ///   - diameter: ボールの直径
    /// - Returns: 生成したボール
    func Ball(offset: CGSize = .zero, diameter: CGFloat = 150) -> some View {
        Circle()
            .fill(.white)
            .frame(width: diameter, height: diameter)
            .offset(offset)
    }
    private var theGradient: LinearGradient {
        .linearGradient(colors: [Color("Gradient1"), Color("Gradient2")],
                        startPoint: .top,
                        endPoint: .bottom)
    }
}

