func convValueToDDC(for command: Command, from: Float) -> UInt16 {
  var value = from
  if self.readPrefAsBool(key: .invertDDC, for: command) {
    value = 1 - value
  }
  let curveMultiplier = self.getCurveMultiplier(self.readPrefAsInt(key: .curveDDC, for: command))
  let minDDCValue = Float(self.readPrefAsInt(key: .minDDCOverride, for: command))
  let maxDDCValue = Float(self.readPrefAsInt(key: .maxDDC, for: command))
  let curvedValue = pow(max(min(value, 1), 0), curveMultiplier)
  let deNormalizedValue = (maxDDCValue - minDDCValue) * curvedValue + minDDCValue
  var intDDCValue = UInt16(min(max(deNormalizedValue, minDDCValue), maxDDCValue))
  if from > 0, command == Command.audioSpeakerVolume {
    intDDCValue = max(1, intDDCValue) // Never let sound to mute accidentally, keep it digitally to at digital 1 if needed as muting breaks some displays
  }
  return intDDCValue
}

extension GlobalEventMonitor {
    /// A publisher that emits global events for an event type mask.
    struct GlobalEventPublisher: Publisher {
        typealias Output = NSEvent
        typealias Failure = Never

        let mask: NSEvent.EventTypeMask

        func receive<S: Subscriber<Output, Failure>>(subscriber: S) {
            let subscription = GlobalEventSubscription(mask: mask, subscriber: subscriber)
            subscriber.receive(subscription: subscription)
        }
    }

    /// Returns a publisher that emits global events for the given event type mask.
    ///
    /// - Parameter mask: An event type mask specifying which events to publish.
    static func publisher(for mask: NSEvent.EventTypeMask) -> GlobalEventPublisher {
        GlobalEventPublisher(mask: mask)
    }
}

private func drawACIcon(ctx: CGContext, center batteryCenter: CGPoint, height: CGFloat, charging: Bool) {
    var points: [CGPoint] = []

    if charging {
        let iconSize: CGSize = CGSize(width: 9, height: height + 6)
        let min = CGPoint(
            x: batteryCenter.x - (iconSize.width/2),
            y: batteryCenter.y - (iconSize.height/2)
        )
        let max = CGPoint(
            x: batteryCenter.x + (iconSize.width/2),
            y: batteryCenter.y + (iconSize.height/2)
        )

        points = [
            CGPoint(x: batteryCenter.x-3, y: min.y), // bottom
            CGPoint(x: max.x, y: batteryCenter.y+1.5),
            CGPoint(x: batteryCenter.x+1, y: batteryCenter.y+1.5),
            CGPoint(x: batteryCenter.x+3, y: max.y), // top
            CGPoint(x: min.x, y: batteryCenter.y-1.5),
            CGPoint(x: batteryCenter.x-1, y: batteryCenter.y-1.5)
        ]
    } else {
        let iconSize: CGSize = CGSize(width: 9, height: height + 2)
        let minY = batteryCenter.y - (iconSize.height/2)
        let maxY = batteryCenter.y + (iconSize.height/2)

        points = [
            CGPoint(x: batteryCenter.x-1.5, y: minY+0.5),

            CGPoint(x: batteryCenter.x+1.5, y: minY+0.5),
            CGPoint(x: batteryCenter.x+1.5, y: batteryCenter.y - 2.5),

            CGPoint(x: batteryCenter.x+4, y: batteryCenter.y + 0.5),
            CGPoint(x: batteryCenter.x+4, y: batteryCenter.y + 4.25),

            // right
            CGPoint(x: batteryCenter.x+2.75, y: batteryCenter.y + 4.25),
            CGPoint(x: batteryCenter.x+2.75, y: maxY-0.25),
            CGPoint(x: batteryCenter.x+0.25, y: maxY-0.25),
            CGPoint(x: batteryCenter.x+0.25, y: batteryCenter.y + 4.25),

            // left
            CGPoint(x: batteryCenter.x-0.25, y: batteryCenter.y + 4.25),
            CGPoint(x: batteryCenter.x-0.25, y: maxY-0.25),
            CGPoint(x: batteryCenter.x-2.75, y: maxY-0.25),
            CGPoint(x: batteryCenter.x-2.75, y: batteryCenter.y + 4.25),

            CGPoint(x: batteryCenter.x-4, y: batteryCenter.y + 4.25),
            CGPoint(x: batteryCenter.x-4, y: batteryCenter.y + 0.5),

            CGPoint(x: batteryCenter.x-1.5, y: batteryCenter.y - 2.5),
            CGPoint(x: batteryCenter.x-1.5, y: minY+0.5)
        ]
    }

    let linePath = NSBezierPath()
    linePath.move(to: CGPoint(x: points[0].x, y: points[0].y))
    for i in 1..<points.count {
        linePath.line(to: CGPoint(x: points[i].x, y: points[i].y))
    }
    linePath.line(to: CGPoint(x: points[0].x, y: points[0].y))

    NSColor.textColor.set()
    linePath.fill()

    ctx.saveGState()
    ctx.setBlendMode(.destinationOut)

    NSColor.textColor.set()
    linePath.lineWidth = 1
    linePath.stroke()

    ctx.restoreGState()
}

