struct UTMAppleConfigurationDisplay: Codable, Identifiable {

    var widthInPixels: Int = 1920

    var heightInPixels: Int = 1200

    var pixelsPerInch: Int = 80

    var isDynamicResolution: Bool = true

    let id = UUID()

    enum CodingKeys: String, CodingKey {
        case widthInPixels = "WidthPixels"
        case heightInPixels = "HeightPixels"
        case pixelsPerInch = "PixelsPerInch"
        case isDynamicResolution = "DynamicResolution"
    }

    init() {
    }

    init(width: Int, height: Int, ppi: Int = 80) {
        widthInPixels = width
        heightInPixels = height
        pixelsPerInch = ppi
    }

    init(from decoder: Decoder) throws {
        let values = try decoder.container(keyedBy: CodingKeys.self)
        widthInPixels = try values.decode(Int.self, forKey: .widthInPixels)
        heightInPixels = try values.decode(Int.self, forKey: .heightInPixels)
        pixelsPerInch = try values.decode(Int.self, forKey: .pixelsPerInch)
        isDynamicResolution = try values.decodeIfPresent(Bool.self, forKey: .isDynamicResolution) ?? true
    }

    func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        try container.encode(widthInPixels, forKey: .widthInPixels)
        try container.encode(heightInPixels, forKey: .heightInPixels)
        try container.encode(pixelsPerInch, forKey: .pixelsPerInch)
        try container.encode(isDynamicResolution, forKey: .isDynamicResolution)
    }

    #if arch(arm64)
    @available(macOS 12, *)
    init(from config: VZMacGraphicsDisplayConfiguration) {
        widthInPixels = config.widthInPixels
        heightInPixels = config.heightInPixels
        pixelsPerInch = config.pixelsPerInch
    }

    @available(macOS 12, *)
    func vzMacDisplay() -> VZMacGraphicsDisplayConfiguration {
        VZMacGraphicsDisplayConfiguration(widthInPixels: widthInPixels,
                                          heightInPixels: heightInPixels,
                                          pixelsPerInch: pixelsPerInch)
    }
    #endif

    @available(macOS 13, *)
    func vzVirtioDisplay() -> VZVirtioGraphicsScanoutConfiguration {
        VZVirtioGraphicsScanoutConfiguration(widthInPixels: widthInPixels,
                                             heightInPixels: heightInPixels)
    }
}

extension ModelMacro: ExtensionMacro { // @attached(extension, conformances:..)
  /*
   @attached(extension, conformances: // the protocols we add automagically
     PersistentModel
   )
   */
  public static func expansion(
    of               macroNode : AttributeSyntax,
    attachedTo     declaration : some DeclGroupSyntax,    // the class
    providingExtensionsOf type : some TypeSyntaxProtocol, // the classtype
    conformingTo conformancesToAdd : [ TypeSyntax ],
    in                 context : some MacroExpansionContext
  ) throws -> [ ExtensionDeclSyntax ]
  {
    guard let classDecl = declaration.as(ClassDeclSyntax.self) else {
      context.diagnose(.modelMacroCanOnlyBeAppliedOnNSManagedObjects,
                       on: macroNode)
      return [] // TBD: rather throw?
    }
    let inheritedTypeNames = classDecl.inheritedTypeNames
    guard inheritedTypeNames.contains("NSManagedObject") ||
          inheritedTypeNames.contains("CoreData.NSManagedObject") else
    {
      context.diagnose(.modelMacroCanOnlyBeAppliedOnNSManagedObjects,
                       on: macroNode)
      return [] // TBD: rather throw?
    }
    guard !inheritedTypeNames.contains("PersistentModel") &&
          !inheritedTypeNames.contains("ManagedModels.PersistentModel") else
    {
      return []
    }
    if !conformancesToAdd.isEmpty { // this isn't always filled?
      var stillNeeded = false
      for conformance in conformancesToAdd {
        guard let id = conformance.as(IdentifierTypeSyntax.self) else {
          assertionFailure("Unexpected conformance? \(conformance)")
          continue
        }
        let name = id.name.trimmed.text
        if name == "PersistentModel" || 
           name == "ManagedModels.PersistentModel"
        {
          stillNeeded = true
        }
        else {
          assertionFailure("Unexpected conformance: \(name)")
        }
      }
      guard stillNeeded else { return [] }
    }
    return [
      try ExtensionDeclSyntax(
        "extension \(type): ManagedModels.PersistentModel"
      ) {}
    ]
  }
}

