private func drawTwoRows(_ x: CGFloat, _ topElement: Stack_t, _ bottomElement: Stack_t?) -> CGFloat {
    let rowHeight: CGFloat = self.frame.height / 2
    var monospacedFontState: Bool = false
    var fixedSizeState: Bool = false
    var alignment: NSTextAlignment = .left
    self.queue.sync {
        monospacedFontState = self.monospacedFontState
        fixedSizeState = self.fixedSizeState
        alignment = self.alignment
    }

    var font: NSFont
    if monospacedFontState {
        font = NSFont.monospacedDigitSystemFont(ofSize: 10, weight: .light)
    } else {
        font = NSFont.systemFont(ofSize: 10, weight: .light)
    }
    let style = NSMutableParagraphStyle()
    style.alignment = alignment

    let attributes = [
        NSAttributedString.Key.font: font,
        NSAttributedString.Key.foregroundColor: NSColor.textColor,
        NSAttributedString.Key.paragraphStyle: style
    ]

    var width: CGFloat = self.twoRowWidth
    if !fixedSizeState {
        let firstRowWidth = topElement.value.widthOfString(usingFont: font)
        let secondRowWidth = bottomElement?.value.widthOfString(usingFont: font) ?? 0
        width = max(20, max(firstRowWidth, secondRowWidth)).rounded(.up) + 2
    }

    var rect = CGRect(x: x, y: rowHeight+1, width: width, height: rowHeight)
    var str = NSAttributedString.init(string: topElement.value, attributes: attributes)
    str.draw(with: rect)

    if bottomElement != nil {
        rect = CGRect(x: x, y: 1, width: width, height: rowHeight)
        str = NSAttributedString.init(string: bottomElement!.value, attributes: attributes)
        str.draw(with: rect)
    }

    return width
}

func calcNewValue(currentValue: Float, isUp: Bool, isSmallIncrement: Bool, half: Bool = false) -> Float {
  let nextValue: Float
  if isSmallIncrement {
    nextValue = currentValue + (isUp ? 0.01 : -0.01)
  } else {
    let osdChicletFromValue = OSDUtils.chiclet(fromValue: currentValue, maxValue: 1, half: half)
    let distance = OSDUtils.getDistance(fromNearestChiclet: osdChicletFromValue)
    var nextFilledChiclet = isUp ? ceil(osdChicletFromValue) : floor(osdChicletFromValue)
    let distanceThreshold: Float = 0.25 // 25% of the distance between the edges of an osd box
    if distance == 0 {
      nextFilledChiclet += (isUp ? 1 : -1)
    } else if !isUp, distance < distanceThreshold {
      nextFilledChiclet -= 1
    } else if isUp, distance > (1 - distanceThreshold) {
      nextFilledChiclet += 1
    }
    nextValue = OSDUtils.value(fromChiclet: nextFilledChiclet, maxValue: 1, half: half)
  }
  return max(0, min(1, nextValue))
}

class CBTConvertCell: CBTConversionOperation
{
    var destinationIndex:Int;
    var frameNumber:Int;
    var cell:HashedCell;
    var lastCellOptional:HashedCell?;
    init(destinationIndex: Int, frameNumber: Int, cell:HashedCell, lastCell:HashedCell?)
    {
        self.destinationIndex = destinationIndex;
        self.frameNumber = frameNumber
        self.cell = cell;
        self.lastCellOptional = lastCell;
    }
    override func main()
    {
        if let lastCell = self.lastCellOptional
        {
            if (cell != lastCell)
            {
                sendWrite();
            }
            else
            {
                NSLog("---[Cell %i in Frame %i Skipped: Static Block]", self.destinationIndex, self.frameNumber);
            }
        }
        else
        {
            sendWrite();
        }
    }
    func sendWrite()
    {
        let sem = dispatch_semaphore_create(0);
        CBTConvertAnimation.imageCoordinator!.addCell(cell, callbackClosure: { (sourceIndex:Int) -> Void in
            CBTConvertAnimation.JSONCoordinator!.addCellData(sourceIndex, destinationIndex: self.destinationIndex, frame: self.frameNumber, callbackClosure: { () -> Void in
                dispatch_semaphore_signal(sem);
            })
        })
        dispatch_semaphore_wait(sem, DISPATCH_TIME_FOREVER);
    }
}

private func calculationMode<KeyframeValue>(
  for keyframes: [Keyframe<KeyframeValue>]
) -> CAAnimationCalculationMode {
  // At this point we expect all of the animations to have been split in
  // to segments based on the `CAAnimationCalculationMode`, so we can just
  // check the first keyframe.
  if keyframes[0].isHold {
    .discrete
  } else {
    .linear
  }
}

extension Promise: Recoverable {
    public func recover(_ body: @escaping (Error) -> T) -> Guarantee<T> {
        return Guarantee<T>(Task.init {
            switch await task.result {
            case .success(let value):
                return value
            case .failure(let error):
                return body(error)
            }
        })
    }
    public func recoverEscaping(_ body: @escaping (Error) -> T) -> Guarantee<T> {
        return recover(body)
    }
    public func recover(_ body: @escaping (Error) throws -> T) -> Self {
        return Self(Task.init {
            switch await task.result {
            case .success(let value):
                return value
            case .failure(let errorOriginal):
                return try body(errorOriginal)
            }
        })
    }
    public func recoverEscaping(_ body: @escaping (Error) throws -> T) -> Self {
        return recover(body)
    }
    public func recover(_ body: @escaping (Error) async -> T) -> Guarantee<T> {
        return Guarantee<T>(Task.init {
            await recoverAsyncBody(body, result: await task.result)
        })
    }
    public func recover(_ body: @escaping (Error) async throws -> T) -> Promise<T> {
        return Promise<T>(Task.init {
            try await recoverAsyncThrowsBody(body, result: await task.result)
        })
    }
}

private func addShadowOpacityAnimation(from model: DropShadowModel, context: LayerAnimationContext) throws {
  guard let opacityKeyframes = model._opacity else { return }

  try addAnimation(
    for: .shadowOpacity,
    keyframes: opacityKeyframes,
    value: {
      // Lottie animation files express opacity as a numerical percentage value
      // (e.g. 0%, 50%, 100%) so we divide by 100 to get the decimal values
      // expected by Core Animation (e.g. 0.0, 0.5, 1.0).
      $0.cgFloatValue / 100
    },
    context: context
  )
}

