def get_combined_config(name, val, default=None):
    """Consolidate the config with priority from high to low provided init
    value > OS environ > default."""

    if val is not None:
        return val

    env = load_dash_env_vars().get(f"DASH_{name.upper()}")
    if env is None:
        return default

    return env.lower() == "true" if env.lower() in {"true", "false"} else env

private func computeWaveform(url: URL, bins: Int) -> [Float]? {
    guard bins > 0 else { return nil }
    // Use autoreleasepool to manage memory from audio buffer allocations
    return autoreleasepool {
        do {
            let audioFile = try AVAudioFile(forReading: url)
            let length = Int(audioFile.length)
            guard length > 0 else { return nil }

            guard let buffer = AVAudioPCMBuffer(pcmFormat: audioFile.processingFormat, frameCapacity: AVAudioFrameCount(length)) else {
                return nil
            }
            try audioFile.read(into: buffer, frameCount: AVAudioFrameCount(length))
            guard let channelData = buffer.floatChannelData else { return nil }

            let channelCount = Int(audioFile.processingFormat.channelCount)
            let frameLength = Int(buffer.frameLength)
            let samplesPerBin = max(1, frameLength / bins)

            var magnitudes: [Float] = Array(repeating: 0, count: bins)
            for bin in 0..<bins {
                let start = bin * samplesPerBin
                let end = min(frameLength, start + samplesPerBin)
                if start >= end { break }

                var sum: Float = 0
                var sampleCount = 0
                for frame in start..<end {
                    var sampleValue: Float = 0
                    for channel in 0..<channelCount {
                        sampleValue += fabsf(channelData[channel][frame])
                    }
                    sum += sampleValue / Float(channelCount)
                    sampleCount += 1
                }
                magnitudes[bin] = sampleCount > 0 ? sum / Float(sampleCount) : 0
            }

            if let maxMagnitude = magnitudes.max(), maxMagnitude > 0 {
                magnitudes = magnitudes.map { min($0 / maxMagnitude, 1.0) }
            }
            return magnitudes
        } catch {
            SecureLogger.error("Waveform extraction failed for \(url.lastPathComponent): \(error)", category: .session)
            return nil
        }
    }
}

private func drawTwoRows() -> CGFloat {
    var width: CGFloat = 7
    var x: CGFloat = 7

    if self.iconAlignmentState == "right" {
        x = 0
    }
    if self.icon == "none" {
        x = 0
        width = 0
    }

    if self.valueState {
        let rowWidth: CGFloat = self.unitsState ? 48 : 30
        let rowHeight: CGFloat = self.frame.height / 2
        let style = NSMutableParagraphStyle()
        style.alignment = self.valueAlignment

        let inputStringAttributes = [
            NSAttributedString.Key.font: NSFont.systemFont(ofSize: 9, weight: .light),
            NSAttributedString.Key.foregroundColor: self.inputColor(self.valueColorState),
            NSAttributedString.Key.paragraphStyle: style
        ]
        let outputStringAttributes = [
            NSAttributedString.Key.font: NSFont.systemFont(ofSize: 9, weight: .light),
            NSAttributedString.Key.foregroundColor: self.outputColor(self.valueColorState),
            NSAttributedString.Key.paragraphStyle: style
        ]

        let inputY: CGFloat = self.displayValueState == "io" ? rowHeight + 1 : 1
        let outputY: CGFloat = self.displayValueState == "io" ? 1 : rowHeight + 1

        var rect = CGRect(x: Constants.Widget.margin.x + x, y: inputY, width: rowWidth - (Constants.Widget.margin.x*2), height: rowHeight)
        let input = NSAttributedString.init(
            string: Units(bytes: self.inputValue).getReadableSpeed(base: base, omitUnits: !self.unitsState),
            attributes: inputStringAttributes
        )
        input.draw(with: rect)

        rect = CGRect(x: Constants.Widget.margin.x + x, y: outputY, width: rowWidth - (Constants.Widget.margin.x*2), height: rowHeight)
        let output = NSAttributedString.init(
            string: Units(bytes: self.outputValue).getReadableSpeed(base: base, omitUnits: !self.unitsState),
            attributes: outputStringAttributes
        )
        output.draw(with: rect)

        width += rowWidth
    }

    switch self.icon {
    case "dots":
        self.drawDots(width)
    case "arrows":
        self.drawArrows(width)
    case "chars":
        self.drawChars(width)
    default: break
    }

    return width
}

