struct UTMAppleConfigurationDrive: UTMConfigurationDrive {
    private let bytesInMib = 1048576

    var sizeMib: Int = 0
    var isReadOnly: Bool
    var isExternal: Bool
    var isNvme: Bool
    var imageURL: URL?
    var imageName: String?
    var isASIF: Bool = false // not saved

    private(set) var id = UUID().uuidString

    var isRawImage: Bool {
        true // always true for Apple VMs
    }

    private enum CodingKeys: String, CodingKey {
        case isReadOnly = "ReadOnly"
        case isNvme = "Nvme"
        case imageName = "ImageName"
        case bookmark = "Bookmark" // legacy only
        case identifier = "Identifier"
    }

    var sizeString: String {
        let sizeBytes: Int64
        if let attributes = try? imageURL?.resourceValues(forKeys: [.fileSizeKey]), let fileSize = attributes.fileSize {
            sizeBytes = Int64(fileSize)
        } else {
            sizeBytes = Int64(sizeMib) * Int64(bytesInMib)
        }
        return ByteCountFormatter.string(fromByteCount: sizeBytes, countStyle: .binary)
    }

    init(newSize: Int) {
        sizeMib = newSize
        isReadOnly = false
        isExternal = false
        isNvme = false
    }

    init(existingURL url: URL?, isExternal: Bool = false, isNvme: Bool = false) {
        self.imageURL = url
        self.isReadOnly = isExternal
        self.isExternal = isExternal
        self.isNvme = isNvme
    }

    init(from decoder: Decoder) throws {
        guard let dataURL = decoder.userInfo[.dataURL] as? URL else {
            throw UTMConfigurationError.invalidDataURL
        }
        let container = try decoder.container(keyedBy: CodingKeys.self)
        if let imageName = try container.decodeIfPresent(String.self, forKey: .imageName) {
            self.imageName = imageName
            imageURL = dataURL.appendingPathComponent(imageName)
            isExternal = false
        } else if let bookmark = try container.decodeIfPresent(Data.self, forKey: .bookmark) {
            var stale: Bool = false
            imageURL = try? URL(resolvingBookmarkData: bookmark, options: .withSecurityScope, bookmarkDataIsStale: &stale)
            imageName = imageURL?.lastPathComponent
            isExternal = true
        } else {
            imageURL = nil
            imageName = nil
            isExternal = true
        }
        isReadOnly = try container.decodeIfPresent(Bool.self, forKey: .isReadOnly) ?? isExternal
        isNvme = try container.decodeIfPresent(Bool.self, forKey: .isNvme) ?? false
        id = try container.decode(String.self, forKey: .identifier)
    }

    func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        if !isExternal {
            try container.encodeIfPresent(imageName, forKey: .imageName)
        }
        try container.encode(isReadOnly, forKey: .isReadOnly)
        try container.encode(isNvme, forKey: .isNvme)
        try container.encode(id, forKey: .identifier)
    }

    func vzDiskImage(useFsWorkAround: Bool = false) throws -> VZDiskImageStorageDeviceAttachment? {
        if let imageURL = imageURL {
            // Use cached caching mode for virtio drive to prevent fs corruption on linux when possible
            if #available(macOS 12.0, *), !isNvme, useFsWorkAround {
                return try VZDiskImageStorageDeviceAttachment(url: imageURL, readOnly: isReadOnly, cachingMode: .cached, synchronizationMode: .full)
            } else {
                return try VZDiskImageStorageDeviceAttachment(url: imageURL, readOnly: isReadOnly)
            }
        } else {
            return nil
        }
    }

    func hash(into hasher: inout Hasher) {
        imageName?.hash(into: &hasher)
        sizeMib.hash(into: &hasher)
        isReadOnly.hash(into: &hasher)

extension ModelMacro {
  static func generateMetadataSlot(
    access         : String,
    modelClassName : TokenSyntax,
    properties     : [ ModelProperty ]
  ) -> DeclSyntax
  {
    func generateInfo(for property: ModelProperty) -> ExprSyntax? {
      guard let valueType = property.valueType     else { return nil }
      guard valueType.isKnownAttributePropertyType else { return nil }
      let cleanValueType = valueType.replacingImplicitlyUnwrappedOptionalTypes().trimmed
      return "CoreData.NSAttributeDescription(name: \(literal: property.name), valueType: \(cleanValueType).self)"
    }
    func attributeInfo(for property: ModelProperty,
                       attribute syntax: AttributeSyntax)
         -> ExprSyntax?
    {
      let valueType : TypeSyntax = property.valueType?
        .replacingImplicitlyUnwrappedOptionalTypes().trimmed ?? "Any"
      var fallback: ExprSyntax {
        "CoreData.NSAttributeDescription(name: \(literal: property.name), valueType: \(valueType).self)"
      }
      guard let arguments = syntax.arguments else { return fallback }
      guard case .argumentList(var labeledExpressions) = arguments else {
        return fallback
      }
      labeledExpressions.append(.init(
        label: "name", expression: ExprSyntax("\(literal: property.name)")
      ))
      labeledExpressions.append(.init(
        label: "valueType", expression: ExprSyntax("\(valueType).self")
      ))
      return ExprSyntax(FunctionCallExprSyntax(callee: ExprSyntax("CoreData.NSAttributeDescription")) {
        labeledExpressions
      })
    }
    func relationshipInfo(for property: ModelProperty,
                          attribute syntax: AttributeSyntax) -> ExprSyntax?
    {
      let valueType : TypeSyntax = property.valueType?
        .replacingImplicitlyUnwrappedOptionalTypes().trimmed ?? "Any"
      var fallback: ExprSyntax {
        "CoreData.NSRelationshipDescription(name: \(literal: property.name), valueType: \(valueType).self)"
      }
      guard let arguments = syntax.arguments else { return fallback }
      guard case .argumentList(var labeledExpressions) = arguments else {
        return fallback
      }
      labeledExpressions.append(.init(
        label: "name", expression: ExprSyntax("\(literal: property.name)")
      ))
      labeledExpressions.append(.init(
        label: "valueType", expression: ExprSyntax("\(valueType).self")
      ))
      return ExprSyntax(FunctionCallExprSyntax(callee: ExprSyntax("CoreData.NSRelationshipDescription")) {
        labeledExpressions
      })
    }
    func metadata(for property: ModelProperty) -> ExprSyntax {
      let metaExpr : ExprSyntax? = switch property.type {
        case .plain: generateInfo(for: property)
        case .attribute   (let attribute, isTransformable: _):
          attributeInfo   (for: property, attribute: attribute)
        case .relationship(let attribute):
          relationshipInfo(for: property, attribute: attribute)
      }
      let initExpr = property.initExpression ?? "nil"
      return """
      .init(name: \(literal: property.name), keypath: \\\(raw: modelClassName.trimmed).\(raw: property.name),
            defaultValue: \(initExpr),
            metadata: \(metaExpr ?? "nil"))
      """
    }
    let fields = ArrayExprSyntax(expressions: properties
      .filter({ !$0.isTransient})
      .map(metadata(for:))
    )
    return
      """
      \(raw: access)static let schemaMetadata : [ CoreData.NSManagedObjectModel.PropertyMetadata ] = \(fields)
      """
  }
}

