public class MotionManager: ObservableObject {
    /// Only one shared MotionManager should be used in an app
    static let shared = MotionManager()
    private init() { }
    static let motionQueue = OperationQueue()
    static let screenSize = UIScreen.main.bounds.size
    static let maxScreenDimension = max(MotionManager.screenSize.height, MotionManager.screenSize.width)
    private let cmManager = CMMotionManager()
    @Published public private(set) var updateInterval: TimeInterval = 0
    @Published public private(set) var disabled: Bool = false
    @Published public private(set) var deviceOrientation: UIDeviceOrientation = .unknown
    /// Rotation of device relative to zero position. Value is updated with SwiftUI animation to smooth between update intervals.
    @Published public private(set) var animatedQuaternion: Quat = .identity
    /// Rotation of device relative to zero position. Value is updated based on update intervals without animation or smoothing.
    @Published public private(set) var quaternion: Quat = .identity
    /// Rotation from zero to initial position of device when motion updates started.
    ///
    /// This value is reset whenever motion manager is re-enabled.
    @Published public private(set) var initialDeviceRotation: Quat? = nil
    /// Rotation from initial device rotation to current.
    public var deltaRotation: Quat {
        guard let initialDeviceRotation = initialDeviceRotation else {
            return .identity
        }
        return (animatedQuaternion * initialDeviceRotation.inverse)
    }
    public var interfaceRotation: Quat {
        switch deviceOrientation {
        case .landscapeLeft:
            return Quat(angle: .radians(-.pi / 2), axis: .zAxis)
        case .landscapeRight:
            return Quat(angle: .radians(.pi / 2), axis: .zAxis)
        case .portraitUpsideDown:
            return Quat(angle: .radians(.pi), axis: .zAxis)
        default:
            return .identity
        }
    }
    /// True if update interval greater than zero and not disabled.
    public var isDetectingMotion: Bool {
        updateInterval > 0 && !disabled
    }
    /// The device screen size taking into account device orientation.
    var interfaceSize: CGSize {
        switch deviceOrientation {
        case .landscapeRight, .landscapeLeft:
            return CGSize(width: Self.screenSize.height, height: Self.screenSize.width)
        default:
            return Self.screenSize
        }
    }
    /// Changes the device orientation property if the new orientation is supported.
    public func changeDeviceOrientation() {
        let newOrientation = UIDevice.current.orientation
        guard deviceOrientation != newOrientation else {
            return
        }
        if InfoDictionary.supportedOrientations.contains(newOrientation) {
            initialDeviceRotation = nil
            self.deviceOrientation = newOrientation
            restartMotionUpdatesIfNeeded()
        }
    }
    /// Sets the update interval to the value specified
    /// - Parameter newUpdateInterval: New update interval
    public func setUpdateInterval(_ newUpdateInterval: TimeInterval) {
        if updateInterval != newUpdateInterval {
            updateInterval = newUpdateInterval
            restartMotionUpdatesIfNeeded()
        }
    }
    /// Sets the disabled property to the value specified
    /// - Parameter newDisabled: New disabled value.
    public func setDisabled(_ newDisabled: Bool) {
        if disabled != newDisabled {
            disabled = newDisabled
            restartMotionUpdatesIfNeeded()
        }
    }
    /// Method to update several properties at once.
    /// - Parameters:
    ///   - updateInterval: Time between motion updates.
    ///   - disabled: If true, motion updates are disabled.
    ///   - setDeviceOrientation: If true, device orientation is updated.
    public func startMotionUpdates(updateInterval: TimeInterval? = nil, disabled: Bool? = nil, setDeviceOrientation: Bool = false) {
        if let disabled, self.disabled != disabled {
            self.disabled = disabled
        }
        if let updateInterval, self.updateInterval != updateInterval {
            self.updateInterval = updateInterval
        }
        if setDeviceOrientation {
            let newOrientation = UIDevice.current.orientation
            if deviceOrientation != newOrientation,
               InfoDictionary.supportedOrientations.contains(newOrientation) {
                initialDeviceRotation = nil
                deviceOrientation = newOrientation
            }
        }
        restartMotionUpdatesIfNeeded()
    }
    /// Restarts motion updates
    public func restart() {
        restartMotionUpdatesIfNeeded()
    }
    /// Stops motion updates. This must be run before deinit. Currently this is done with `.onDisappear()` in ``MotionManagerViewModifier``
    public func stopMotionUpdates() {
        if cmManager.isDeviceMotionActive {
            cmManager.stopDeviceMotionUpdates()
        }
    }
    /// Toggles motion updates off if on or on if off (and not disabled and update interval greater than zero).
    private func restartMotionUpdatesIfNeeded() {
        stopMotionUpdates()
        guard updateInterval > 0 && !disabled else { return }
        cmManager.deviceMotionUpdateInterval = updateInterval
        cmManager.startDeviceMotionUpdates(to: .main) { motionData, error in
            if let motionData = motionData {
                let quaternion = Quat(motionData.attitude.quaternion)
                if self.initialDeviceRotation == nil {
                    self.initialDeviceRotation = quaternion
                }
                self.quaternion = quaternion
                withAnimation(Animation.linear(duration: self.updateInterval)) {
                    self.animatedQuaternion = quaternion
                }
            } else if let error = error {
                print(error.localizedDescription)
            } else {
                print("Error - Unknown motion update error")
            }
        }
    }
}

func setupCurrentAndMaxValues(command: Command, firstrun: Bool = false) {
  var ddcValues: (UInt16, UInt16)?
  var maxDDCValue = UInt16(DDC_MAX_DETECT_LIMIT)
  var currentDDCValue: UInt16
  switch command {
  case .audioSpeakerVolume: currentDDCValue = UInt16(Float(DDC_MAX_DETECT_LIMIT) * 0.125)
  case .contrast: currentDDCValue = UInt16(Float(DDC_MAX_DETECT_LIMIT) * 0.750)
  default: currentDDCValue = UInt16(Float(DDC_MAX_DETECT_LIMIT) * 1.000)
  }
  if command == .audioSpeakerVolume {
    currentDDCValue = UInt16(Float(DDC_MAX_DETECT_LIMIT) * 0.125) // lower default audio value as high volume might rattle the user.
  }
  os_log("Setting up display %{public}@ for %{public}@", type: .info, String(self.identifier), String(reflecting: command))
  if !self.isSw() {
    if prefs.integer(forKey: PrefKey.startupAction.rawValue) == StartupAction.read.rawValue, self.pollingCount != 0, !app.safeMode {
      os_log("- Reading DDC from display %{public}@ times", type: .info, String(self.pollingCount))
      let delay = self.readPrefAsBool(key: .longerDelay) ? UInt64(40 * kMillisecondScale) : nil
      ddcValues = self.readDDCValues(for: command, tries: UInt(self.pollingCount), minReplyDelay: delay)
      if ddcValues != nil {
        (currentDDCValue, maxDDCValue) = ddcValues ?? (currentDDCValue, maxDDCValue)
        self.processCurrentDDCValue(isReadFromDisplay: true, command: command, firstrun: firstrun, currentDDCValue: currentDDCValue)
        os_log("- DDC read successful.", type: .info)
      } else {
        os_log("- DDC read failed.", type: .info)
      }
    } else {
      os_log("- DDC read disabled.", type: .info)
    }
    if self.readPrefAsInt(key: .maxDDCOverride, for: command) > self.readPrefAsInt(key: .minDDCOverride, for: command) {
      self.savePref(self.readPrefAsInt(key: .maxDDCOverride, for: command), key: .maxDDC, for: command)
    } else {
      self.savePref(min(Int(maxDDCValue), DDC_MAX_DETECT_LIMIT), key: .maxDDC, for: command)
    }
    if ddcValues == nil {
      self.processCurrentDDCValue(isReadFromDisplay: false, command: command, firstrun: firstrun, currentDDCValue: currentDDCValue)
      currentDDCValue = self.getDDCValueFromPrefs(command)
    }
    os_log("- Current DDC value: %{public}@", type: .info, String(currentDDCValue))
    os_log("- Minimum DDC value: %{public}@ (overrides 0)", type: .info, String(self.readPrefAsInt(key: .minDDCOverride, for: command)))
    os_log("- Maximum DDC value: %{public}@ (overrides %{public}@)", type: .info, String(self.readPrefAsInt(key: .maxDDC, for: command)), String(maxDDCValue))
    os_log("- Current internal value: %{public}@", type: .info, String(self.readPrefAsFloat(for: command)))
    os_log("- Command status: %{public}@", type: .info, self.readPrefAsBool(key: .isTouched, for: command) ? "Touched" : "Untouched")
    if command == .audioSpeakerVolume {
      self.setupMuteUnMute()
    }
    self.restoreDDCSettingsToDisplay(command: command)
  } else {
    self.savePref(self.prefExists(for: command) ? self.readPrefAsFloat(for: command) : Float(1), for: command)
    self.savePref(self.readPrefAsFloat(for: command), key: .SwBrightness)
    self.brightnessSyncSourceValue = self.readPrefAsFloat(for: command)
    self.smoothBrightnessTransient = self.readPrefAsFloat(for: command)
    os_log("- Software controlled display current internal value: %{public}@", type: .info, String(self.readPrefAsFloat(for: command)))
  }
}

struct DefaultSectorView: View {
    @Binding var progress: CGFloat
    private let count: Int = 8
    @State private var rotationAngle: Angle = .radians(0)
    public var body: some View {
        GeometryReader { geometry in
            Group {
                ForEach(0..<count, id: \.self) { index in
                    DefaultSectorItemView(index: index, count: count, size: geometry.size)
                        .opacity(progress * 2.0 - CGFloat(index) * 1 / CGFloat(count) - 0.1)
                        .animation(.linear, value: progress)
                }
            }
            .rotationEffect(rotationAngle)
            .frame(width: geometry.size.width, height: geometry.size.height)
            .onChange(of: progress) { _ in
                if progress > 1.0 {
                    withAnimation(.linear(duration: 1)) {
                        rotationAngle = .radians(.pi * 2.0)
                    }
                } else {
                    rotationAngle = .zero
                }
            }
        }
    }
}

private func defaultAnimation<KeyframeValue: AnyInterpolatable, ValueRepresentation>(
  for property: LayerProperty<ValueRepresentation>,
  keyframes keyframeGroup: KeyframeGroup<KeyframeValue>,
  value keyframeValueMapping: (KeyframeValue) throws -> ValueRepresentation,
  context: LayerAnimationContext
) throws -> CAAnimation? {
  let keyframes = keyframeGroup.keyframes
  guard !keyframes.isEmpty else { return nil }

  // Check if this set of keyframes uses After Effects expressions, which aren't supported.
  //  - We only log this once per `CoreAnimationLayer` instance.
  if keyframeGroup.unsupportedAfterEffectsExpression != nil, !context.loggingState.hasLoggedAfterEffectsExpressionsWarning {
    context.loggingState.hasLoggedAfterEffectsExpressionsWarning = true
    context.logger.info("""
      `\(property.caLayerKeypath)` animation for "\(context.currentKeypath.fullPath)" \
      includes an After Effects expression (https://helpx.adobe.com/after-effects/using/expression-language.html), \
      which is not supported by lottie-ios (expressions are only supported by lottie-web). \
      This animation may not play correctly.
      """)
  }

  // If there is exactly one keyframe value that doesn't animate,
  // we can improve performance by applying that value directly to the layer
  // instead of creating a relatively expensive `CAKeyframeAnimation`.
  if keyframes.count == 1 {
    return singleKeyframeAnimation(
      for: property,
      keyframeValue: try keyframeValueMapping(keyframes[0].value),
      writeDirectlyToPropertyIfPossible: true
    )
  }

  /// If we're required to use the `complexTimeRemapping` from some parent `PreCompLayer`,
  /// we have to manually interpolate the keyframes with the time remapping applied.
  if context.mustUseComplexTimeRemapping {
    return try defaultAnimation(
      for: property,
      keyframes: Keyframes.manuallyInterpolatedWithTimeRemapping(keyframeGroup, context: context),
      value: keyframeValueMapping,
      context: context.withoutTimeRemapping()
    )
  }

  // Split the keyframes into segments with the same `CAAnimationCalculationMode` value
  //  - Each of these segments will become their own `CAKeyframeAnimation`
  let animationSegments = keyframes.segmentsSplitByCalculationMode()

  // If we only have a single segment, we can just create a single `CAKeyframeAnimation`
  // instead of wrapping it in a `CAAnimationGroup` -- this reduces allocation overhead a bit.
  if animationSegments.count == 1 {
    return try keyframeAnimation(
      for: property,
      keyframes: animationSegments[0],
      value: keyframeValueMapping,
      context: context
    )
  } else {
    return try animationGroup(
      for: property,
      animationSegments: animationSegments,
      value: keyframeValueMapping,
      context: context
    )
  }
}

public class Label: WidgetWrapper {
    private var label: String

    internal init(title: String, config: NSDictionary) {
        if let title = config["Title"] as? String {
            self.label = title
        } else {
            self.label = title
        }

        super.init(.label, title: title, frame: CGRect(
            x: 0,
            y: Constants.Widget.margin.y,
            width: 6 + (2*Constants.Widget.margin.x),
            height: Constants.Widget.height - (2*Constants.Widget.margin.y)
        ))

        self.canDrawConcurrently = true
    }

    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }

    public override func draw(_ dirtyRect: NSRect) {
        super.draw(dirtyRect)

        let size: CGSize = CGSize(width: 6, height: self.frame.height / 3)
        var margin: CGPoint = CGPoint(x: Constants.Widget.margin.x, y: 0)
        let style = NSMutableParagraphStyle()
        style.alignment = .center

        let stringAttributes = [
            NSAttributedString.Key.font: NSFont.systemFont(ofSize: 7, weight: .regular),
            NSAttributedString.Key.foregroundColor: NSColor.textColor,
            NSAttributedString.Key.paragraphStyle: style
        ]

        for char in String(self.label.prefix(3)).uppercased().reversed() {
            let rect = CGRect(x: margin.x, y: margin.y, width: size.width, height: size.height)
            let str = NSAttributedString.init(string: "\(char)", attributes: stringAttributes)
            str.draw(with: rect)
            margin.y += size.height
        }
    }
}

public class WebViewStore: ObservableObject {
  @Published public var webView: WKWebView {
    didSet {
      setupObservers()
    }
  }
  public init(webView: WKWebView = WKWebView()) {
    self.webView = webView
    setupObservers()
  }
  private func setupObservers() {
    func subscriber<Value>(for keyPath: KeyPath<WKWebView, Value>) -> NSKeyValueObservation {
      return webView.observe(keyPath, options: [.prior]) { [weak self] _, change in
        guard let self else { return }
        if change.isPrior {
          objectWillChange.send()
        }
      }
    }
    observers = [
      subscriber(for: \.title),
      subscriber(for: \.url),
      subscriber(for: \.isLoading),
      subscriber(for: \.estimatedProgress),
      subscriber(for: \.hasOnlySecureContent),
      subscriber(for: \.serverTrust),
      subscriber(for: \.canGoBack),
      subscriber(for: \.canGoForward)
    ]
    if #available(iOS 15.0, macOS 12.0, *) {
      observers += [
        subscriber(for: \.themeColor),
        subscriber(for: \.underPageBackgroundColor),
        subscriber(for: \.microphoneCaptureState),
        subscriber(for: \.cameraCaptureState)
      ]
    }
#if swift(>=5.7)
    if #available(iOS 16.0, macOS 13.0, *) {
      observers.append(subscriber(for: \.fullscreenState))
    }
#else
    if #available(iOS 15.0, macOS 12.0, *) {
      observers.append(subscriber(for: \.fullscreenState))
    }
#endif
  }
  private var observers: [NSKeyValueObservation] = []
  public subscript<T>(dynamicMember keyPath: KeyPath<WKWebView, T>) -> T {
    webView[keyPath: keyPath]
  }
}

extension Hotkey {
    /// An object that manges the lifetime of a hotkey observation.
    private final class Listener {
        private weak var appState: AppState?

        private var id: UInt32?

        var isValid: Bool {
            id != nil
        }

        init?(hotkey: Hotkey, eventKind: HotkeyRegistry.EventKind, appState: AppState?) {
            guard
                let appState,
                hotkey.keyCombination != nil
            else {
                return nil
            }
            let id = appState.hotkeyRegistry.register(
                hotkey: hotkey,
                eventKind: eventKind
            ) { [weak appState] in
                guard let appState else {
                    return
                }
                Task {
                    await hotkey.action.perform(appState: appState)
                }
            }
            guard let id else {
                return nil
            }
            self.appState = appState
            self.id = id
        }

        deinit {
            invalidate()
        }

        func invalidate() {
            guard isValid else {
                return
            }
            guard let appState else {
                Logger.hotkey.error("Error invalidating hotkey: Missing AppState")
                return
            }
            defer {
                id = nil
            }
            if let id {
                appState.hotkeyRegistry.unregister(id)
            }
        }
    }
}

