func startRecording() throws -> URL {
    try queue.sync {
        if recorder?.isRecording == true {
            throw RecorderError.recordingInProgress
        }

        #if os(iOS)
        let session = AVAudioSession.sharedInstance()
        guard session.recordPermission == .granted else {
            throw RecorderError.microphoneAccessDenied
        }
        #if targetEnvironment(simulator)
        // allowBluetoothHFP is not available on iOS Simulator
        try session.setCategory(
            .playAndRecord,
            mode: .default,
            options: [.defaultToSpeaker, .allowBluetoothA2DP]
        )
        #else
        try session.setCategory(
            .playAndRecord,
            mode: .default,
            options: [.defaultToSpeaker, .allowBluetoothA2DP, .allowBluetoothHFP]
        )
        #endif
        try session.setActive(true, options: .notifyOthersOnDeactivation)
        #endif
        #if os(macOS)
        guard AVCaptureDevice.authorizationStatus(for: .audio) == .authorized else {
            throw RecorderError.microphoneAccessDenied
        }
        #endif

        let outputURL = try makeOutputURL()
        let settings: [String: Any] = [
            AVFormatIDKey: kAudioFormatMPEG4AAC,
            AVSampleRateKey: 16_000,
            AVNumberOfChannelsKey: 1,
            AVEncoderBitRateKey: 16_000
        ]

        let audioRecorder = try AVAudioRecorder(url: outputURL, settings: settings)
        audioRecorder.delegate = self
        audioRecorder.isMeteringEnabled = true
        audioRecorder.prepareToRecord()
        audioRecorder.record(forDuration: maxRecordingDuration)

        recorder = audioRecorder
        currentURL = outputURL
        stopWorkItem?.cancel()
        stopWorkItem = nil
        return outputURL
    }
}

struct AccessibilityPreferences {

  /// Adjusts an animation to be instantaneous if the IINA setting `Disable animations` is enabled.
  /// - Parameter duration: Desired animation duration.
  /// - Returns: `0` if animations have been disabled; otherwise the given duration.
  static func adjustedDuration(_ duration: TimeInterval) -> TimeInterval {
    return Preference.bool(for: PK.disableAnimations) ? 0 : duration
  }

  /// Reflects whether the macOS accessibility setting to reduce motion is in an enabled state.
  ///
  /// This property provides a wrapper around the `NSWorkspace` property so that code that needs to check this setting does not
  /// need to concern itself with this setting not being available until macOS Sierra.
  ///
  /// Proper handling of the Reduce motion setting is covered in the Apple [Human Interface Guidelines](https://developer.apple.com/design/human-interface-guidelines/) under
  /// [Accessibility - Motion](https://developer.apple.com/design/human-interface-guidelines/accessibility#Motion).
  ///
  /// To enable the
  /// [Reduced motion](https://support.apple.com/guide/mac-help/stop-or-reduce-onscreen-motion-mchlc03f57a1/mac)
  /// setting:
  /// - Click on `System Settings…` under the  menu
  /// - The `System Settings` window appears
  /// - On the left side of the window click on `Accessibility`
  /// - On the right side of the window click on `Display`
  /// - In the `Display` section look for the `Reduced motion` setting
  /// - Slide the toggle button to be on (blue)
  /// - Returns: `true` if reduce motion is enabled; otherwise `false`.
  static var motionReductionEnabled: Bool {
    return NSWorkspace.shared.accessibilityDisplayShouldReduceMotion
  }
}

struct MotionManagerViewModifier: ViewModifier {
    @ObservedObject var motionManager = MotionManager.shared
    let updateInterval: TimeInterval
    let disabled: Bool
    func body(content: Content) -> some View {
        content
            .environmentObject(motionManager)
            .onReceive(NotificationCenter.default.publisher(for: UIDevice.orientationDidChangeNotification)) { _ in
                motionManager.changeDeviceOrientation()
            }
            .onReceive(NotificationCenter.default.publisher(for: UIApplication.willEnterForegroundNotification)) { _ in
                motionManager.startMotionUpdates(updateInterval: updateInterval, disabled: disabled, setDeviceOrientation: true)
            }
            .onReceive(NotificationCenter.default.publisher(for: UIApplication.didEnterBackgroundNotification)) { _ in
                motionManager.stopMotionUpdates()
            }
            .onAppear {
                motionManager.startMotionUpdates(updateInterval: updateInterval, disabled: disabled, setDeviceOrientation: true)
            }
            .onDisappear {
                motionManager.stopMotionUpdates()
            }
            .onChange(of: updateInterval) {
                motionManager.setUpdateInterval($0)
            }
            .onChange(of: disabled) {
                motionManager.setDisabled($0)
            }
    }
}

private func path<KeyframeValue>(
  keyframes positionKeyframes: [Keyframe<KeyframeValue>],
  value keyframeValueMapping: (KeyframeValue) throws -> CGPoint
) rethrows -> CGPath {
  let path = CGMutablePath()

  for (index, keyframe) in positionKeyframes.enumerated() {
    if index == positionKeyframes.indices.first {
      path.move(to: try keyframeValueMapping(keyframe.value))
    }

    if index != positionKeyframes.indices.last {
      let nextKeyframe = positionKeyframes[index + 1]

      if
        let controlPoint1 = keyframe.spatialOutTangent?.pointValue,
        let controlPoint2 = nextKeyframe.spatialInTangent?.pointValue,
        !(controlPoint1 == .zero && controlPoint2 == .zero)
      {
        path.addCurve(
          to: try keyframeValueMapping(nextKeyframe.value),
          control1: try keyframeValueMapping(keyframe.value) + controlPoint1,
          control2: try keyframeValueMapping(nextKeyframe.value) + controlPoint2
        )
      }

      else {
        path.addLine(to: try keyframeValueMapping(nextKeyframe.value))
      }
    }
  }

  path.closeSubpath()
  return path
}

