extension ModelMacro {
  static func findModelProperties(in classDecl: ClassDeclSyntax,
                                  errorNode: AttributeSyntax,
                                  context: some MacroExpansionContext)
              -> [ ModelProperty ]
  {
    var properties = [ ModelProperty ]()
    for member : MemberBlockItemSyntax in classDecl.memberBlock.members {
      addModelProperties(in: member.decl, to: &properties,
                         context: context)
    }
    return properties
  }
  /**
   * This creates a `ModelProperty` object/value for each property in the
   * given `VariableDeclSyntax`.
   *
   * A variable decl is something like this:
   * ```swift
   * @Relationship(inverse: \.blub)
   * var street, city, country : String
   * ```
   * Note that attributes (e.g. `@Relationship` is one) are attached to the
   * whole declaration, but the declaration can have multiple "bindings",
   * i.e. properties.
   *
   * It uses the `propertyType` function below to look for the attributes.
   */
  static func addModelProperties<T>(in member: T,
                                    to properties: inout [ ModelProperty ],
                                    context: some MacroExpansionContext)
    where T: SyntaxProtocol
  {
    guard let variables = member.as(VariableDeclSyntax.self) else {
      return
    }
    guard !variables.isStaticOrClass else { return }
    let ( propertyType, isTransient ) = propertyType(
      for: variables.attributes, context: context
    )
    for binding : PatternBindingSyntax in variables.bindings {
      guard binding.accessorBlock == nil else {
        continue
      }
      guard let pattern = binding.pattern.as(IdentifierPatternSyntax.self) else
      {
        continue
      }
      let name = pattern.identifier.trimmed.text
      guard !forbiddenPropertyNames.contains(name) else {
        context.diagnose(.propertyNameIsForbidden,
                         on: member)
        continue
      }
      properties.append(ModelProperty(
        binding: binding,
        type: propertyType,
        name: name,
        declaredValueType: binding.typeAnnotation?.type, // w/o the `:`
        isTransient: isTransient,
        initExpression: binding.initializer?.value // w/o the `=`
      ))
    }
  }
  private static func propertyType(
    for attributes: AttributeListSyntax,
    context: some MacroExpansionContext
  ) -> ( propertyType : ModelProperty.PropertyType, isTransient: Bool )
  {
    var propertyType = ModelProperty.PropertyType.plain
    var isTransient  = false
    for attribute : AttributeListSyntax.Element in attributes {
      switch attribute {
        case .ifConfigDecl(_):
          continue
        case .attribute(let attribute):
          guard let name = attribute
            .attributeName.as(IdentifierTypeSyntax.self)?
            .name.trimmed.text else
          {
            continue
          }
          switch name {
            case "Transient":
              assert(!isTransient, "Transient macro applied twice!")
              isTransient = true
            case "Attribute":
              switch propertyType {
                case .plain:
                  propertyType = .attribute(
                    attribute,
                    isTransformable: isTransformableAttribute(attribute)
                  )
                case .attribute(_, _):
                  context.diagnose(.multipleAttributeMacrosAppliedOnProperty,
                                   on: attributes)
                case .relationship(_):
                  context.diagnose(
                    .attributeAndRelationshipMacrosAppliedOnProperty,
                    on: attributes
                  )
              }
            case "Relationship":
              switch propertyType {
                case .plain:
                  propertyType = .relationship(attribute)
                case .relationship(_):
                  context.diagnose(
                    .multipleRelationshipMacrosAppliedOnProperty,
                    on: attributes
                  )
                case .attribute(_, _):
                  context.diagnose(
                    .attributeAndRelationshipMacrosAppliedOnProperty,
                    on: attributes
                  )
              }
            default:
              break
          }
      }
    }
    return ( propertyType, isTransient )
  }
  private static func isTransformableAttribute(_ syntax: AttributeSyntax)
                      -> Bool
  {
    guard let arguments = syntax.arguments,
          case .argumentList(let labeledExpressions) = arguments else
    {
      return false
    }
    for labeledExpression in labeledExpressions {
      guard labeledExpression.label == nil else { break }
      guard let funCall = labeledExpression.expression
                            .as(FunctionCallExprSyntax.self),
            let member = funCall.calledExpression
                            .as(MemberAccessExprSyntax.self)
      else {
        continue
      }
      guard case .identifier(let name) =
              member.declName.baseName.tokenKind else
      {
        continue
      }
      if name == "transformable" { return true }
    }
    return false
  }
}

struct UTMAppleConfigurationMacPlatform: Codable {
    var hardwareModel: Data
    var machineIdentifier: Data
    var auxiliaryStorageURL: URL?

    private enum CodingKeys: String, CodingKey {
        case hardwareModel = "HardwareModel"
        case machineIdentifier = "MachineIdentifier"
        case auxiliaryStoragePath = "AuxiliaryStoragePath"
    }

    init(from decoder: Decoder) throws {
        guard let dataURL = decoder.userInfo[.dataURL] as? URL else {
            throw UTMConfigurationError.invalidDataURL
        }
        let container = try decoder.container(keyedBy: CodingKeys.self)
        hardwareModel = try container.decode(Data.self, forKey: .hardwareModel)
        machineIdentifier = try container.decode(Data.self, forKey: .machineIdentifier)
        if let auxiliaryStoragePath = try container.decodeIfPresent(String.self, forKey: .auxiliaryStoragePath) {
            auxiliaryStorageURL = dataURL.appendingPathComponent(auxiliaryStoragePath)
        }
    }

    func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        try container.encode(hardwareModel, forKey: .hardwareModel)
        try container.encode(machineIdentifier, forKey: .machineIdentifier)
        try container.encodeIfPresent(auxiliaryStorageURL?.lastPathComponent, forKey: .auxiliaryStoragePath)
    }

    #if arch(arm64)
    @available(macOS 12, *)
    init(newHardware: VZMacHardwareModel) {
        hardwareModel = newHardware.dataRepresentation
        machineIdentifier = VZMacMachineIdentifier().dataRepresentation
    }

    @available(macOS 12, *)
    init(from config: VZMacPlatformConfiguration) {
        hardwareModel = config.hardwareModel.dataRepresentation
        machineIdentifier = config.machineIdentifier.dataRepresentation
        auxiliaryStorageURL = config.auxiliaryStorage?.url
    }

    @available(macOS 12, *)
    func vzMacPlatform() -> VZMacPlatformConfiguration? {
        guard let vzHardwareModel = VZMacHardwareModel(dataRepresentation: hardwareModel) else {
            return nil
        }
        guard let vzMachineIdentifier = VZMacMachineIdentifier(dataRepresentation: machineIdentifier) else {
            return nil
        }
        var vzAuxiliaryStorage: VZMacAuxiliaryStorage?
        if let auxiliaryStorageURL = auxiliaryStorageURL {
            vzAuxiliaryStorage = VZMacAuxiliaryStorage(contentsOf: auxiliaryStorageURL)
        }
        let config = VZMacPlatformConfiguration()
        config.hardwareModel = vzHardwareModel
        config.machineIdentifier = vzMachineIdentifier
        config.auxiliaryStorage = vzAuxiliaryStorage
        return config
    }
    #endif
}

