import re

def analyze_log_file(file_path):
    error_counts = {}
    error_patterns = {
        'ERROR': r'ERROR: (.*)',
        'WARNING': r'WARNING: (.*)'
    }
    for error_type in error_patterns:
        error_counts[error_type] = 0

    with open(file_path, 'r') as f:
        for line in f:
            for error_type, pattern in error_patterns.items():
                match = re.search(pattern, line)
                if match:
