public extension LazyPager {
    func onDismiss(backgroundOpacity: Binding<CGFloat>? = nil, _ callback: @escaping () -> ()) -> LazyPager {
        guard config.direction == .horizontal else {
            return self
        }
        var this = self
        this.config.backgroundOpacity = backgroundOpacity
        this.config.dismissCallback = callback
        return this
    }
    func onTap(_ callback: @escaping () -> ()) -> LazyPager {
        var this = self
        this.config.tapCallback = callback
        return this
    }
    func onDoubleTap(_ callback: @escaping () -> ()) -> LazyPager {
        var this = self
        this.config.doubleTapCallback = callback
        return this
    }
    func onDrag(_ callback: @escaping () -> ()) -> LazyPager {
        var this = self
        this.config.dragCallback = callback
        return this
    }
    func pageSpacing(_ spacing: CGFloat) -> LazyPager {
        var this = self
        this.config.pageSpacing = spacing
        return this
    }
    func shouldLoadMore(on: LoadMore = .lastElement(minus: 3), _ callback: @escaping () -> ()) -> LazyPager {
        var this = self
        this.config.loadMoreOn = on
        this.config.loadMoreCallback = callback
        return this
    }
    func zoomable(min: CGFloat, max: CGFloat, doubleTapGesture: DoubleTap = .scale(0.5)) -> LazyPager {
        var this = self
        this.config.zoomConfigGetter = { _ in
            return .custom(min: min, max: max, doubleTap: doubleTapGesture)
        }
        return this
    }
    func zoomable(onElement: @escaping (Element) -> ZoomConfig) -> LazyPager {
        var this = self
        this.config.zoomConfigGetter = onElement
        return this
    }
    func settings(_ adjust: @escaping (inout Config<Element>) -> ()) -> LazyPager {
        var this = self
        adjust(&this.config)
        return this
    }
    func overscroll(_ callback: @escaping (ListPosition) -> ()) -> LazyPager {
        var this = self
        this.config.overscrollCallback = callback
        return this
    }
    func absoluteContentPosition(_ absoluteContentPosition: Binding<CGFloat>? = nil) -> LazyPager {
        guard config.direction == .horizontal else {
            return self
        }
        var this = self
        this.config.absoluteContentPosition = absoluteContentPosition
        return this
    }
    func onZoom(_ onZoomHandler: @escaping (Element, CGFloat) -> ()) -> LazyPager {
        var this = self
        this.config.onZoomHandler = onZoomHandler
        return this
    }
}

struct ParticlePortraitColorView: View {
    @StateObject private var vm = PortraitSystem()
    @State private var ready = false
    @State private var lastCanvas: CGSize = .zero
    var body: some View {
        ZStack {
            LinearGradient(colors: [.black, .black.opacity(0.98)],
                           startPoint: .top, endPoint: .bottom)
                .ignoresSafeArea()
            TimelineView(.animation(minimumInterval: 1/60)) { timeline in
                GeometryReader { _ in
                    let now = timeline.date
                    Canvas(rendersAsynchronously: true) { ctx, size in
                        guard size.width > 2, size.height > 2 else { return }
                        if !ready || abs(size.width - lastCanvas.width) > 1 || abs(size.height - lastCanvas.height) > 1 {
                            DispatchQueue.main.async {
                                vm.build(from: "Steve", canvas: size)
                                lastCanvas = size
                                ready = true
                            }
                            return
                        }
                        let tNow: CGFloat = .init(now.timeIntervalSince(vm.animStart))
                        let dots = vm.dots
                        if dots.isEmpty {
                            drawFallbackNoise(ctx: ctx, size: size)
                            return
                        }
                        if vm.assembling {
                            for d in dots {
                                let t = clamp01((tNow - CGFloat(d.delay)) / vm.assembleTime)
                                let k1 = smoothstep(t)
                                let k  = smoothstep(k1)
                                let drift = (1 - k) * (1 - k) * d.sway * 0.6
                                let x = lerp(d.start.x, d.end.x, k) + sin(d.angle + k * 6) * drift
                                let y = lerp(d.start.y, d.end.y, k) + cos(d.angle * 0.8 + k * 5) * drift * 0.6
                                let pulse = 0.96 + 0.04 * (0.5 + 0.5 * sin((tNow + CGFloat(d.delay)) * 0.8))
                                let sizePx = max(1, d.baseSize * pulse)
                                drawDot(ctx: ctx, x: x, y: y, size: sizePx, color: d.color, glow: vm.useGlow)
                            }
                        } else {
                            for d in dots {
                                let tt = tNow + CGFloat(d.delay)
                                let ox = cos(d.angle + tt * d.speed) * d.orbit
                                let oy = sin(d.angle * 0.8 + tt * d.speed * 1.2) * d.orbit
                                let x = d.start.x + ox
                                let y = d.start.y + oy
                                let breath = 0.9 + 0.1 * (0.5 + 0.5 * sin(tt * (0.6 + d.speed)))
                                let sizePx = max(1, d.baseSize * breath)
                                drawDot(ctx: ctx, x: x, y: y, size: sizePx, color: d.color, glow: vm.useGlow)
                            }
                        }
                    }
                    .contentShape(Rectangle())
                    .onTapGesture { vm.toggle() }
                }
            }
            VStack {
                HStack {
                    Text("dots: \(vm.dots.count)")
                        .font(.caption.monospacedDigit())
                        .foregroundColor(.white.opacity(0.60))
                        .padding(8)
                    Spacer()
                }
                Spacer()
                Text(vm.assembling ? "Tap to scatter" : "Tap to assemble")
                    .font(.footnote.weight(.medium))
                    .foregroundColor(.white.opacity(0.65))
                    .padding(.bottom, 24)
            }
            .padding(.horizontal, 12)
            .allowsHitTesting(false)
        }
        .statusBarHidden(true)
    }
    private func drawDot(ctx: GraphicsContext,
                         x: CGFloat, y: CGFloat,
                         size: CGFloat, color: Color,
                         glow: Bool) {
        if glow {
            var g = Path()
            let gsz = size * 3.0
            g.addEllipse(in: CGRect(x: x - (gsz - size)/2, y: y - (gsz - size)/2, width: gsz, height: gsz))
            ctx.fill(g, with: .color(color.opacity(0.08)))
        }
        var dot = Path()
        dot.addEllipse(in: CGRect(x: x, y: y, width: size, height: size))
        ctx.fill(dot, with: .color(color))
    }
    private func drawFallbackNoise(ctx: GraphicsContext, size: CGSize) {
        let n = Int((size.width * size.height) / 4500)
        for _ in 0..<n {
            let x = CGFloat.random(in: 0..<size.width)
            let y = CGFloat.random(in: 0..<size.height)
            let s = CGFloat.random(in: 0.6...1.6)
            var p = Path()
            p.addEllipse(in: CGRect(x: x, y: y, width: s, height: s))
            ctx.fill(p, with: .color(.white.opacity(0.25)))
        }
    }
}

extension LocalEventMonitor {
    /// A publisher that emits local events for an event type mask.
    struct LocalEventPublisher: Publisher {
        typealias Output = NSEvent
        typealias Failure = Never

        let mask: NSEvent.EventTypeMask

        func receive<S: Subscriber<Output, Failure>>(subscriber: S) {
            let subscription = LocalEventSubscription(mask: mask, subscriber: subscriber)
            subscriber.receive(subscription: subscription)
        }
    }

    /// Returns a publisher that emits local events for the given event type mask.
    ///
    /// - Parameter mask: An event type mask specifying which events to publish.
    static func publisher(for mask: NSEvent.EventTypeMask) -> LocalEventPublisher {
        LocalEventPublisher(mask: mask)
    }
}

private func drawOneRow(value: String, x: CGFloat) -> CGFloat {
    let attributes = [
        NSAttributedString.Key.font: NSFont.systemFont(ofSize: 12, weight: .regular),
        NSAttributedString.Key.foregroundColor: isDarkMode ? NSColor.white : NSColor.textColor,
        NSAttributedString.Key.paragraphStyle: NSMutableParagraphStyle()
    ]

    let rowWidth = value.widthOfString(usingFont: .systemFont(ofSize: 12, weight: .regular))
    let rect = CGRect(x: x, y: (Constants.Widget.height-12)/2, width: rowWidth, height: 12)
    let str = NSAttributedString.init(string: value, attributes: attributes)
    str.draw(with: rect)

    return rowWidth
}

