            let fileManager = FileManager.default
            let efiVariableStorageURL = dataURL.appendingPathComponent(QEMUPackageFileName.efiVariables.rawValue)
            if !fileManager.fileExists(atPath: efiVariableStorageURL.path) {
                _ = try VZEFIVariableStore(creatingVariableStoreAt: efiVariableStorageURL)
            }
            self.linuxKernelURL = nil
            self.linuxInitialRamdiskURL = nil
            self.linuxCommandLine = nil
            self.efiVariableStorageURL = efiVariableStorageURL
            urls.append(efiVariableStorageURL)
        }
        let vmSavedStateURL = dataURL.appendingPathComponent(QEMUPackageFileName.vmState.rawValue)
        self.vmSavedStateURL = vmSavedStateURL
        urls.append(vmSavedStateURL)
        return urls
    }
}

extension AsyncSequence {
    /// Assigns each element from an async sequence to a property on an object.
    ///
    /// ```swift
    /// class MyClass {
    ///     var value: Int = 0 {
    ///         didSet { print("Set to \(self.value)") }
    ///     }
    /// }
    ///
    ///
    /// let sequence = AsyncStream<Int> { continuation in
    ///     continuation.yield(1)
    ///     continuation.yield(2)
    ///     continuation.yield(3)
    ///     continuation.finish()
    /// }
    ///
    /// let object = MyClass()
    /// sequence.assign(to: \.value, on: object)
    ///
    /// // Prints:
    /// // Set to 1
    /// // Set to 2
    /// // Set to 3
    /// ```
    ///
    /// - Parameters:
    ///   - keyPath: A key path to indicate the property to be assign.
    ///   - object: The object that contains the property.
    /// - Returns: A `Task<Void, Error>`. It is not required to keep reference to the task,
    /// but it does give the ability to cancel the assign by calling `cancel()`.
    @discardableResult
    public func assign<Root>(
        to keyPath: ReferenceWritableKeyPath<Root, Element>,
        on object: Root
    ) rethrows -> Task<Void, Error> where Self: Sendable, Root: Sendable {
        Task {
            for try await element in self {
                object[keyPath: keyPath] = element
            }
        }
    }
    /// The first element of the sequence, if there is one.
    public func first() async rethrows -> Element? {
        try await self.first { _ in
            true
        }
    }
    /// The last element of the sequence, if there is one.
    public func last() async rethrows -> Element? {
        var latestElement: Element?
        for try await element in self {
            latestElement = element
        }
        return latestElement
    }
    /// Collect elements from a sequence.
    ///
    /// ```swift
    /// // Collect all elements.
    /// var values = await self.sequence.collect()
    /// print(values)
    ///
    /// // Prints:
    /// // [1, 2, 3]
    ///
    /// // Collect only 2 elements.
    /// values = await self.sequence.collect(2)
    /// print(values)
    ///
    /// // Prints:
    /// // [1, 2]
    /// ```
    ///
    /// - Parameter numberOfElements: The number of elements to collect. By default
    /// this is `nil` which indicates all elements will be collected. If the number of elements
    /// in the sequence is less than the number of elements requested, then all the elements will
    /// be collected.
    /// - Returns: Returns: An array of all elements.
    public func collect(_ numberOfElements: Int? = .none) async rethrows -> [Element] {
        var results: [Element] = []
        for try await element in self {
            results.append(element)
            if let numberOfElements = numberOfElements,
               results.count >= numberOfElements {
               break
            }
        }
        return results
    }
    /// Consume the async sequence and pass the element's to a closure.
    ///
    /// ```swift
    /// let sequence = .init { continuation in
    ///     continuation.yield(1)
    ///     continuation.yield(2)
    ///     continuation.yield(3)
    ///     continuation.finish()
    /// }
    ///
    /// sequence.sink { print($0) }
    ///
    /// // Prints:
    /// // 1
    /// // 2
    /// // 3
    /// ```
    /// - Parameters:
    ///   - priority: The priority of the task. Pass nil to use the priority from `Task.currentPriority`.
    ///   - receiveValue: The closure to execute on receipt of a value.
    /// - Returns: A task instance.
    @discardableResult
    public func sink(
        priority: TaskPriority? = nil,
        receiveValue: @Sendable @escaping (Element) async -> Void
    ) -> Task<Void, Error> where Self: Sendable {
        Task(priority: priority) {
            for try await element in self {
                await receiveValue(element)
                try Task.checkCancellation()
            }
        }
    }
    /// Consume the async sequence and pass the element's and it's completion
    /// state to two closures.
    ///
    /// ```swift
    /// let sequence = .init { continuation in
    ///     continuation.yield(1)
    ///     continuation.yield(2)
    ///     continuation.yield(3)
    ///     continuation.finish(throwing: TestError())
    /// }
    ///
    /// sequence.sink(
    ///     receiveValue: { print("Value: \($0)") },
    ///     receiveCompletion: { print("Complete: \($0)") }
    /// )
    ///
    /// // Prints:
    /// // Value: 1
    /// // Value: 2
    /// // Value: 3
    /// // Complete: failure(TestError())
    /// ```
    /// - Parameters:
    ///   - priority: The priority of the task. Pass nil to use the priority from `Task.currentPriority`.
    ///   - receiveValue: The closure to execute on receipt of a value.
    ///   - receiveCompletion: The closure to execute on completion.
    /// - Returns: A task instance.
    @discardableResult
    public func sink(
        priority: TaskPriority? = nil,
        receiveValue: @Sendable @escaping (Element) async -> Void,
        receiveCompletion: @Sendable @escaping (AsyncSequenceCompletion<Error>) async -> Void
    ) -> Task<Void, Never> where Self: Sendable {
        Task(priority: priority) {
            do {
                for try await element in self {
                    await receiveValue(element)
                    try Task.checkCancellation()
                }
                try Task.checkCancellation()
                await receiveCompletion(.finished)
            } catch {
                await receiveCompletion(.failure(error))
            }
        }
    }
}

extension AsyncStream {
    /// Construct a AsyncStream buffering given an Element type.
    ///
    /// - Parameter elementType: The type the AsyncStream will produce.
    /// - Parameter maxBufferedElements: The maximum number of elements to
    ///   hold in the buffer past any checks for continuations being resumed.
    /// - Parameter build: The work associated with yielding values to the
    ///   AsyncStream.
    ///
    /// The maximum number of pending elements limited by dropping the oldest
    /// value when a new value comes in if the buffer would excede the limit
    /// placed upon it. By default this limit is unlimited.
    ///
    /// The build closure passes in a Continuation which can be used in
    /// concurrent contexts. It is thread safe to send and finish; all calls are
    /// to the continuation are serialized, however calling this from multiple
    /// concurrent contexts could result in out of order delivery.
    public init(
        _ elementType: Element.Type = Element.self,
        bufferingPolicy limit: AsyncStream<Element>.Continuation.BufferingPolicy = .unbounded,
        _ build: @escaping (AsyncStream<Element>.Continuation) async -> Void
    ) {
        self = AsyncStream(elementType, bufferingPolicy: limit) { continuation in
            let task = Task {
                await build(continuation)
            }
            continuation.onTermination = { _ in
                task.cancel()
            }
        }
    }
}

