func updateInstalledPrograms() {
    let driveC = url.appending(path: "drive_c")
    var programs: [Program] = []
    var foundURLS: Set<URL> = []

    for folderName in ["Program Files", "Program Files (x86)"] {
        let folderURL = driveC.appending(path: folderName)
        let enumerator = FileManager.default.enumerator(
            at: folderURL, includingPropertiesForKeys: [.isExecutableKey], options: [.skipsHiddenFiles]
        )

        while let url = enumerator?.nextObject() as? URL {
            guard !url.hasDirectoryPath && url.pathExtension == "exe" else { continue }
            guard !settings.blocklist.contains(url) else { continue }
            foundURLS.insert(url)
            programs.append(Program(url: url, bottle: self))
        }
    }

    // Add missing programs from pins
    for pin in settings.pins {
        guard let url = pin.url else { continue }
        guard !foundURLS.contains(url) else { continue }
        programs.append(Program(url: url, bottle: self))
    }

    self.programs = programs.sorted { $0.name.lowercased() < $1.name.lowercased() }
}

private func handleShowOnClick() {
    guard
        let appState,
        appState.settingsManager.generalSettingsManager.showOnClick,
        isMouseInsideEmptyMenuBarSpace
    else {
        return
    }

    Task {
        // Short delay helps the toggle action feel more natural.
        try? await Task.sleep(for: .milliseconds(50))

        if NSEvent.modifierFlags == .control {
            handleShowRightClickMenu()
        } else if
            NSEvent.modifierFlags == .option,
            appState.settingsManager.advancedSettingsManager.canToggleAlwaysHiddenSection
        {
            if let alwaysHiddenSection = appState.menuBarManager.section(withName: .alwaysHidden) {
                alwaysHiddenSection.toggle()
            }
        } else {
            if let hiddenSection = appState.menuBarManager.section(withName: .hidden) {
                hiddenSection.toggle()
            }
        }
    }
}

extension DropShadowEffect: DropShadowModel {
  var _color: KeyframeGroup<LottieColor>? {
    color?.value
  }

  var _distance: KeyframeGroup<LottieVector1D>? {
    distance?.value
  }

  var _radius: KeyframeGroup<LottieVector1D>? {
    softness?.value?.map { softnessValue in
      // After Effects shadow softness uses a different range of values than CALayer.shadowRadius,
      // so shadows render too softly if we directly use the value from After Effects. We find that
      // dividing this value from After Effects by 5 produces results that are visually similar.
      LottieVector1D(softnessValue.cgFloatValue / 5)
    }
  }

  var _opacity: KeyframeGroup<LottieVector1D>? {
    opacity?.value?.map { originalOpacityValue in
      // `DropShadowEffect.opacity` is a value between 0 and 255,
      // but `DropShadowModel._opacity` expects a value between 0 and 100.
      LottieVector1D((originalOpacityValue.value / 255.0) * 100)
    }
  }

  var _angle: KeyframeGroup<LottieVector1D>? {
    direction?.value?.map { originalAngleValue in
      // `DropShadowEffect.distance` is rotated 90º from the
      // angle value representation expected by `DropShadowModel._angle`
      LottieVector1D(originalAngleValue.value - 90)
    }
  }
}

def doc2rst(doc, arglist=True, raw=False):
    """
    arglist  : bool, whether to create argument lists
    raw  : bool, ignores arglist and indents by 10 spaces
    """
    doc = doc.replace('`', '``')
    if raw:
        doc = doc.replace('\n', '\n          ')
        doc = doc.replace('\n          \n', '\n\n')
    else:
        doc = dedent(doc)
        if arglist:
            doc = '\n'.join(i if not i or i[0] == ' ' else '* ' + i + '  '
                            for i in doc.split('\n'))
    return doc

private func drawChars(_ width: CGFloat) {
    let rowHeight: CGFloat = self.frame.height / 2
    let inputY: CGFloat = self.displayValueState == "io" ? rowHeight+1 : 1
    let outputY: CGFloat = self.displayValueState == "io" ? 1 : rowHeight+1
    let x: CGFloat = self.iconAlignmentState == "left" ? Constants.Widget.margin.x : Constants.Widget.margin.x+(width-6)

    let inputAttributes = [
        NSAttributedString.Key.font: NSFont.systemFont(ofSize: 9, weight: .regular),
        NSAttributedString.Key.foregroundColor: self.inputColor(self.iconColorState),
        NSAttributedString.Key.paragraphStyle: NSMutableParagraphStyle()
    ]
    var rect = CGRect(x: x, y: inputY, width: 8, height: rowHeight)
    var str = NSAttributedString.init(string: self.symbols.input, attributes: inputAttributes)
    str.draw(with: rect)

    let outputAttributes = [
        NSAttributedString.Key.font: NSFont.systemFont(ofSize: 9, weight: .regular),
        NSAttributedString.Key.foregroundColor: self.outputColor(self.iconColorState),
        NSAttributedString.Key.paragraphStyle: NSMutableParagraphStyle()
    ]
    rect = CGRect(x: x, y: outputY, width: 8, height: rowHeight)
    str = NSAttributedString.init(string: self.symbols.output, attributes: outputAttributes)
    str.draw(with: rect)
}

struct BezierPathKeyframe: Interpolatable {
  let path: BezierPath
  let cornerRadius: LottieVector1D?

  /// Creates a single array of animatable keyframes from the given sets of keyframes
  /// that can have different counts / timing parameters
  static func combining(
    path: KeyframeGroup<BezierPath>,
    cornerRadius: KeyframeGroup<LottieVector1D>?
  ) throws -> KeyframeGroup<BezierPathKeyframe> {
    guard
      let cornerRadius,
      cornerRadius.keyframes.contains(where: { $0.value.cgFloatValue > 0 })
    else {
      return path.map { path in
        BezierPathKeyframe(path: path, cornerRadius: nil)
      }
    }

    return Keyframes.combined(
      path,
      cornerRadius,
      makeCombinedResult: BezierPathKeyframe.init
    )
  }

  func interpolate(to: BezierPathKeyframe, amount: CGFloat) -> BezierPathKeyframe {
    BezierPathKeyframe(
      path: path.interpolate(to: to.path, amount: amount),
      cornerRadius: cornerRadius.interpolate(to: to.cornerRadius, amount: amount)
    )
  }
}

def get_installed_libraries(api_client, cluster_id):
    """Returns the installed PyPI packages and the ones that failed.

    Args:
        api_client (ApiClient object): object used for authenticating to the workspace
        cluster_id (str): id of the cluster

    Returns:
        Dict[str, str]: dictionary of {package: status}
    """
    cluster_status = LibrariesApi(api_client).cluster_status(cluster_id)
    libraries = {
        lib["library"]["pypi"]["package"]: lib["status"]
        for lib in cluster_status["library_statuses"]
        if "pypi" in lib["library"]
    }
    return {
        pkg_resources.Requirement.parse(package).name: libraries[package]
        for package in libraries
    }

extension Hotkey: Codable {
    private enum CodingKeys: CodingKey {
        case keyCombination
        case action
    }

    convenience init(from decoder: any Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        try self.init(
            keyCombination: container.decode(KeyCombination?.self, forKey: .keyCombination),
            action: container.decode(HotkeyAction.self, forKey: .action)
        )
    }

    func encode(to encoder: any Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        try container.encode(keyCombination, forKey: .keyCombination)
        try container.encode(action, forKey: .action)
    }
}

struct UTMAppleConfigurationBoot: Codable {
    enum OperatingSystem: String, CaseIterable, QEMUConstant {
        case none = "None"
        case linux = "Linux"
        case macOS = "macOS"

        var prettyValue: String {
            switch self {
            case .none: return NSLocalizedString("None", comment: "UTMAppleConfigurationBoot")
            case .linux: return NSLocalizedString("Linux", comment: "UTMAppleConfigurationBoot")
            case .macOS: return NSLocalizedString("macOS", comment: "UTMAppleConfigurationBoot")
            }
        }
    }

    var operatingSystem: OperatingSystem
    var linuxKernelURL: URL?
    var linuxCommandLine: String?
    var linuxInitialRamdiskURL: URL?
    var efiVariableStorageURL: URL?
    var vmSavedStateURL: URL?
    var hasUefiBoot: Bool = false

    /// IPSW for installing macOS. Not saved.
    var macRecoveryIpswURL: URL?

    private enum CodingKeys: String, CodingKey {
        case operatingSystem = "OperatingSystem"
        case linuxKernelPath = "LinuxKernelPath"
        case linuxCommandLine = "LinuxCommandLine"
        case linuxInitialRamdiskPath = "LinuxInitialRamdiskPath"
        case efiVariableStoragePath = "EfiVariableStoragePath"
