static func previewBodies(from content: String, defaultEnabled: Bool) -> [String]? {
    let lines = content.split(separator: "\n", omittingEmptySubsequences: false)
    var previewBodies: [String] = []
    var currentBody: String = ""
    var previewWasFound = false
    var viewMustBeLoaded = defaultEnabled
    var braceBalance: Int? = nil
    for line in lines {
        if line.hasPrefix(Constants.previewMarker) {
            previewWasFound = true
            currentBody = ""
            braceBalance = nil
        }
        guard previewWasFound else { continue }
        let braceChange = line.reduce(0) { (count, char) in
            if char == Constants.openingBrace {
                return count + 1
            } else if char == Constants.closingBrace {
                return count - 1
            }
            return count
        }
        if braceChange != 0 || braceBalance != nil {
            braceBalance = (braceBalance ?? 0) + braceChange
        }
        if defaultEnabled {
            if line.contains(Constants.prefireDisableMarker) {
                viewMustBeLoaded = false
            }
        } else if !viewMustBeLoaded {
            viewMustBeLoaded = line.contains(Constants.prefireEnabledMarker)
        }
        currentBody.append(String(line) + "\n")
        if braceBalance == 0 {
            if !currentBody.isEmpty, viewMustBeLoaded {
                previewBodies.append(currentBody)
            }
            previewWasFound = false
            viewMustBeLoaded = defaultEnabled
        }
    }
    return previewBodies.isEmpty ? nil : previewBodies
}

final class EllipseDrawingTool: DrawingTool {
    typealias Stroke = EllipseStroke
    static func drawStroke(_ stroke: EllipseStroke, inContext context: CGContext) {
        context.setBlendMode(.copy)
        context.setStrokeColor(stroke.strokeColor.cgColor)
        context.setLineWidth(stroke.strokeWidth)
        context.strokeEllipse(in: .init(from: stroke.startPoint, to: stroke.endPoint))
    }
    var delegate: DrawingToolDelegate?
    let strokeColor: UIColor
    let strokeWidth: CGFloat
    var startPoint: CGPoint?
    var endPoint: CGPoint?
    init(strokeColor: UIColor, strokeWidth: CGFloat) {
        self.strokeColor = strokeColor
        self.strokeWidth = strokeWidth
    }
    func startedPan(atPoint point: CGPoint) {
        startPoint = point
    }
    func continuedPan(atPoint point: CGPoint) {
        guard let startPoint else { return }
        endPoint = point
        delegate?.drawingToolSetNeedsDisplay(self)
    }
    func finishedPan(atPoint point: CGPoint) {
        guard let startPoint else { return }
        let stroke = Stroke(
            strokeColor: strokeColor,
            strokeWidth: strokeWidth,
            startPoint: startPoint,
            endPoint: point
        )
        self.startPoint = nil
        self.endPoint = nil
        delegate?.drawingTool(self, didCreateStroke: stroke)
    }
    func drawCurrentStroke(inContext context: CGContext) {
        guard let startPoint, let endPoint else { return }
        context.setBlendMode(.copy)
        context.setStrokeColor(strokeColor.cgColor)
        context.setLineWidth(strokeWidth)
        context.strokeEllipse(in: .init(from: startPoint, to: endPoint))
    }
}

/// Log details about when and from what sources IINA was built.
  ///
  /// For developers that take a development build to other machines for testing it is useful to log information that can be used to
  /// distinguish between development builds.
  ///
  /// In support of this the build populated `Info.plist` with keys giving:
  /// - The build date
  /// - The git branch
  /// - The git commit
  private func logBuildDetails() {
    guard let date = InfoDictionary.shared.buildDate,
          let sdk = InfoDictionary.shared.buildSDK,
          let xcode = InfoDictionary.shared.buildXcode else { return }
    let toString = DateFormatter()
    toString.dateStyle = .medium
    toString.timeStyle = .medium
    // Always use the en_US locale for dates in the log file.
    toString.locale = Locale(identifier: "en_US")
    Logger.log("Built using Xcode \(xcode) and macOS SDK \(sdk) on \(toString.string(from: date))")
    guard let branch = InfoDictionary.shared.buildBranch,
          let commit = InfoDictionary.shared.buildCommit else { return }
    Logger.log("From branch \(branch), commit \(commit)")
  }

