def is_palindrome(s):
  s = s.lower()
  return s == s[::-1]

private func drawValue(_ value: Int64, offset: CGPoint, color: NSColor) -> CGFloat {
    let rowWidth: CGFloat = self.unitsState ? 58 : 32
    let height: CGFloat = self.frame.height
    let style = NSMutableParagraphStyle()
    style.alignment = self.valueAlignment
    let size: CGFloat = 10

    let inputStringAttributes = [
        NSAttributedString.Key.font: NSFont.systemFont(ofSize: 11, weight: .regular),
        NSAttributedString.Key.foregroundColor: color,
        NSAttributedString.Key.paragraphStyle: style
    ]

    let rect = CGRect(x: offset.x, y: (height-size)/2 + offset.y + 1, width: rowWidth - (Constants.Widget.margin.x*2), height: size)
    let value = NSAttributedString.init(
        string: Units(bytes: value).getReadableSpeed(base: base, omitUnits: !self.unitsState),
        attributes: inputStringAttributes
    )
    value.draw(with: rect)

    return rowWidth
}

func asyncPerformWriteDDCValues(command: Command) {
  var value = UInt16.max
  var lastValue = UInt16.max
  self.writeDDCQueue.sync {
    value = self.writeDDCNextValue[command] ?? UInt16.max
    lastValue = self.writeDDCLastSavedValue[command] ?? UInt16.max
  }
  guard value != UInt16.max, value != lastValue else {
    return
  }
  self.writeDDCQueue.async(flags: .barrier) {
    self.writeDDCLastSavedValue[command] = value
    self.savePref(true, key: PrefKey.isTouched, for: command)
  }
  var controlCodes = self.getRemapControlCodes(command: command)
  if controlCodes.count == 0 {
    controlCodes.append(command.rawValue)
  }
  for controlCode in controlCodes {
    if Arm64DDC.isArm64 {
      if self.arm64ddc {
        _ = Arm64DDC.write(service: self.arm64avService, command: controlCode, value: value)
      }
    } else {
      _ = self.ddc?.write(command: controlCode, value: value, errorRecoveryWaitTime: 2000) ?? false
    }
  }
}

extension Bridging {
    /// Options that determine the space identifiers to return in a space list.
    enum SpaceListOption {
        case allSpaces, visibleSpaces
    }

    /// The identifier of the active space.
    static var activeSpaceID: CGSSpaceID {
        CGSGetActiveSpace(CGSMainConnectionID())
    }

    /// Returns an array of identifiers for the spaces containing the window with
    /// the given identifier.
    ///
    /// - Parameter windowID: An identifier for a window.
    static func getSpaceList(for windowID: CGWindowID, option: SpaceListOption) -> [CGSSpaceID] {
        let mask: CGSSpaceMask = switch option {
        case .allSpaces: .allSpaces
        case .visibleSpaces: .allVisibleSpaces
        }
        guard let spaces = CGSCopySpacesForWindows(CGSMainConnectionID(), mask, [windowID] as CFArray) else {
            Logger.bridging.error("CGSCopySpacesForWindows failed")
            return []
        }
        guard let spaceIDs = spaces.takeRetainedValue() as? [CGSSpaceID] else {
            Logger.bridging.error("CGSCopySpacesForWindows returned array of unexpected type")
            return []
        }
        return spaceIDs
    }

    /// Returns a Boolean value that indicates whether the window with the
    /// given identifier is on the active space.
    ///
    /// - Parameter windowID: An identifier for a window.
    static func isWindowOnActiveSpace(_ windowID: CGWindowID) -> Bool {
        getSpaceList(for: windowID, option: .allSpaces).contains(activeSpaceID)
    }

    /// Returns a Boolean value that indicates whether the space with the given
    /// identifier is a fullscreen space.
    ///
    /// - Parameter spaceID: An identifier for a space.
    static func isSpaceFullscreen(_ spaceID: CGSSpaceID) -> Bool {
        let type = CGSSpaceGetType(CGSMainConnectionID(), spaceID)
        return type == .fullscreen
    }
}

internal extension Image {
  init(image: _Image, scale: CGFloat = 1.0) {
#if os(iOS) || os(visionOS)
    self.init(uiImage: image)
#else
    if scale > 1.0 {
      let scaledSize = NSSize(
          width: image.size.width / scale,
          height: image.size.height / scale
      )
      let scaledImage = image.resized(to: scaledSize)
      if let representation = image.representations.first {
        scaledImage.addRepresentation(representation)
      }
      self.init(nsImage: scaledImage)
      return
    }
    self.init(nsImage: image)
#endif
  }
}

